import BasePermissions from "./BasePermissions";
import { useAppSelector } from "~/store/hooks";
import { __ } from "@wordpress/i18n";

const Copy = ({
    rolesOptions,
    usersOptions,
}: {
    rolesOptions: { name: string; value: string }[];
    usersOptions: { name: string; value: string }[];
}) => {
    const { edit_data } = useAppSelector((state) => state?.widget_builder);
    const copy = edit_data?.data?.permissions?.copy;

    return (
        <BasePermissions
            enable={copy?.enable || false}
            enableTitle={__("Copy", "ninja-drive")}
            enableDescription={__(
                "Allow users to copy files and folders.",
                "ninja-drive",
            )}
            filterDescription={__(
                "Select users & roles who can copy files and folders.",
                "ninja-drive",
            )}
            selectedAccessType={copy?.user_access || "everyone"}
            selectedUserType={copy?.logged_in_user_type || "users"}
            saveBaseKey="copy"
            rolesOptions={rolesOptions}
            usersOptions={usersOptions}
            selectedRolesOrUsers={copy?.display_for || []}
        />
    );
};

export default Copy;
