import { FileIconInline } from "../file-icon";
import { FileActions } from "../file-actions";
import { formatFileSize } from "~/utils/file";
import { TemplateProps } from "../types";

export function CompactView({
    files,
    settings,
    permissions,
    handleActions,
    widget_id,
}: TemplateProps) {
    const { actions, date, extension, thumbnail, size } =
        settings.list_display || {};
    return (
        <div className="pnpnd-file-compact">
            {files.map((file) => (
                <div
                    key={file.id}
                    className="pnpnd-file-compact__item"
                    title={file.additional_data?.base_name}
                    onClick={() => handleActions("preview", file)}
                >
                    <div className="pnpnd-file-compact__left">
                        {thumbnail.enable && (
                            <FileIconInline widget_id={widget_id} file={file} />
                        )}
                        <span className="pnpnd-file-compact__name">
                            {file.additional_data?.base_name}
                        </span>
                    </div>

                    <div className="pnpnd-file-compact__right">
                        {size.enable && (
                            <span className="pnpnd-file-compact__size">
                                {formatFileSize(file.size || 0)}
                            </span>
                        )}

                        {actions.enable && (
                            <FileActions
                                actionExecuter={(action) =>
                                    handleActions(action, file)
                                }
                                compact
                                permissions={permissions}
                            />
                        )}
                    </div>
                </div>
            ))}
        </div>
    );
}
