import * as WPElement from "@wordpress/element";
import PreviewFileUploader from "./index.tsx";

function renderShortcode(element) {
    const shortcodeId = element.getAttribute("data-id");

    if (shortcodeId) {
        const data = window[shortcodeId];

        // Data may not be available yet (e.g. form-builder previews fetch it
        // asynchronously and re-render afterwards).
        if (!data) {
            return;
        }

        if (data.type !== "file_uploader") {
            console.error(
                `Element with ID ${shortcodeId} is not a File Uploader shortcode.`,
            );
            return;
        }

        const component = <PreviewFileUploader data={data} />;

        if (WPElement.createRoot) {
            WPElement.createRoot(element).render(component);
        } else {
            WPElement.render(component, element);
        }
    } else {
        console.error("No File Uploader shortcode ID found.");
    }
}

export const checkAndRenderElements = () => {
    const elements = document.querySelectorAll(".pnpnd-file_uploader");
    if (elements.length === 0) {
        return;
    }
    elements.forEach((element) => {
        if (element.hasAttribute("data-id")) {
            element.setAttribute("data-rendered", "true");
            renderShortcode(element);
        }
    });
};

checkAndRenderElements();
