import { updatePermissions } from "~/store/features/widgetBuilderSlice";
import { useAppDispatch, useAppSelector } from "~/store/hooks";
import Description from "~/components/molecules/Description";
import InlineStack from "~/components/molecules/InlineStack";
import BlockStack from "~/components/molecules/BlockStack";
import Checkbox from "~/components/atoms/Checkbox";
import Divider from "~/components/atoms/Divider";
import BasePermissions from "./BasePermissions";
import Radio from "~/components/atoms/Radio";
import Text from "~/components/atoms/Text";
import { __ } from "@wordpress/i18n";

const Preview = ({
    rolesOptions,
    usersOptions,
}: {
    rolesOptions: { name: string; value: string }[];
    usersOptions: { name: string; value: string }[];
}) => {
    const { edit_data } = useAppSelector((state) => state?.widget_builder);
    const preview = edit_data?.data?.permissions?.preview;

    const dispatch = useAppDispatch();

    return (
        <BasePermissions
            enable={preview?.enable || false}
            enableTitle={__("Preview", "ninja-drive")}
            enableDescription={__(
                "Allow users to preview files.",
                "ninja-drive",
            )}
            filterDescription={__(
                "Select users & roles who can preview files.",
                "ninja-drive",
            )}
            selectedAccessType={preview?.user_access || "everyone"}
            selectedUserType={preview?.logged_in_user_type || "users"}
            saveBaseKey="preview"
            rolesOptions={rolesOptions}
            usersOptions={usersOptions}
            selectedRolesOrUsers={preview?.display_for || []}
            extraContent={
                <BlockStack gap={20}>
                    <InlineStack gap={10}>
                        <Text color="gray-700" size="sm" weight="medium">
                            {__("Preview Mode", "ninja-drive")}
                        </Text>

                        {["inline", "pop_out"].map((mode) => (
                            <Radio
                                key={mode}
                                title={__(
                                    mode === "inline"
                                        ? "Popup"
                                        : "Open In New Tab",
                                    "ninja-drive",
                                )}
                                checked={
                                    (mode === "inline" && preview?.inline) ||
                                    (mode === "pop_out" && preview?.pop_out)
                                }
                                onChange={() =>
                                    dispatch(
                                        updatePermissions({
                                            key: "preview",
                                            value: {
                                                ...edit_data?.data?.permissions
                                                    ?.preview!,
                                                pop_out: mode === "pop_out",
                                                inline: mode === "inline",
                                            },
                                        }),
                                    )
                                }
                            />
                        ))}
                    </InlineStack>

                    <Divider width="100%" height="1px" />

                    {preview?.inline && (
                        <>
                            <BlockStack gap={10}>
                                <Checkbox
                                    rounded="sm"
                                    title={__(
                                        "Show Preview Thumbnails",
                                        "ninja-drive",
                                    )}
                                    checked={
                                        preview?.preview_thumbnail || false
                                    }
                                    onChange={() =>
                                        dispatch(
                                            updatePermissions({
                                                key: "preview",
                                                value: {
                                                    ...edit_data?.data
                                                        ?.permissions?.preview!,
                                                    preview_thumbnail:
                                                        !preview?.preview_thumbnail,
                                                },
                                            }),
                                        )
                                    }
                                />

                                <Description
                                    text={__(
                                        "Show/ hide the file thumbnails at the bottom of the lightbox preview.",
                                        "ninja-drive",
                                    )}
                                />
                            </BlockStack>

                            <Divider width="100%" height="1px" />
                        </>
                    )}
                </BlockStack>
            }
        />
    );
};

export default Preview;
