import { useLazyGetModuleQuery } from "~/store/api/widgetApi";
import InlineStack from "~/components/molecules/InlineStack";
import BlockStack from "~/components/molecules/BlockStack";
import { ModuleConfig } from "../types/widget.types";
import Card from "~/components/molecules/Card";
import Button from "~/components/atoms/Button";
import { useState } from "@wordpress/element";
import Input from "~/components/atoms/Input";
import Icon from "~/components/atoms/Icon";
import Text from "~/components/atoms/Text";
import { __ } from "@wordpress/i18n";

const Password = ({
    data,
    setWidgetData,
}: {
    data: ModuleConfig;
    setWidgetData: React.Dispatch<React.SetStateAction<ModuleConfig>>;
}) => {
    const [password, setPassword] = useState<string>("");
    const [errorMessage, setErrorMessage] = useState<string>("");
    const [getModule] = useLazyGetModuleQuery();
    const [showPassword, setShowPassword] = useState(true);
    const [loading, setLoading] = useState(false);

    const handlePasswordSubmit = async () => {
        setLoading(true);
        try {
            const result = await getModule({
                id: data.id,
                password: password,
            }).unwrap();

            if (!result?.data?.widget?.error_type) {
                (window as any)[`PNPND_${data?.id}`] = result?.data
                    ?.widget as ModuleConfig;

                setWidgetData(result?.data?.widget as ModuleConfig);
                return;
            } else {
                setErrorMessage(
                    result?.data?.widget?.message ?? "Incorrect password",
                );
            }
        } catch (error) {
            setErrorMessage(error as string);
        } finally {
            setLoading(false);
        }
    };

    return (
        <Card>
            <BlockStack gap={15} align="center" inlineAlign="center">
                <BlockStack gap={10} align="center" inlineAlign="center">
                    <Icon name="encrypted" fontSize="6xl" />

                    <Text as="h5" size="lg" weight="semibold" color="black">
                        {data?.message}
                    </Text>

                    <Text as="p" size="sm" color="gray-500">
                        Enter the secret password to access this.
                    </Text>
                </BlockStack>

                <InlineStack gap={10} align="center" wrap={false}>
                    <InlineStack
                        style={{
                            position: "relative",
                        }}
                    >
                        <Input
                            id="password"
                            type={showPassword ? "text" : "password"}
                            placeholder={__("Enter password", "ninja-drive")}
                            size="small"
                            value={password}
                            onChange={(value) => {
                                setErrorMessage("");
                                setPassword(value as string);
                            }}
                            error={!!errorMessage}
                        />

                        <Icon
                            name={
                                showPassword ? "visibility_off" : "visibility"
                            }
                            style={{
                                position: "absolute",
                                right: 10,
                                top: "50%",
                                transform: "translateY(-50%)",
                                cursor: "pointer",
                            }}
                            onClick={() => setShowPassword(!showPassword)}
                        />
                    </InlineStack>

                    <Button
                        variant="primary"
                        size="small"
                        startIcon="check"
                        onClick={handlePasswordSubmit}
                        loading={loading}
                    >
                        Submit
                    </Button>
                </InlineStack>

                {!!errorMessage && (
                    <Text size="sm" color="error">
                        {errorMessage}
                    </Text>
                )}
            </BlockStack>
        </Card>
    );
};

export default Password;
