import { StyleFileBrowser, TPreviewStyle } from "~/types/widget.types";
import { updateStyle } from "~/store/features/widgetBuilderSlice";
import PageContainer from "~/components/molecules/PageContainer";
import SettingsField from "~/components/molecules/SettingsField";
import { useAppDispatch, useAppSelector } from "~/store/hooks";
import InlineStack from "~/components/molecules/InlineStack";
import Description from "~/components/molecules/Description";
import BlockStack from "~/components/molecules/BlockStack";
import Checkbox from "~/components/atoms/Checkbox";
import Divider from "~/components/atoms/Divider";
import { toBoolean } from "~/utils/functions";
import Input from "~/components/atoms/Input";
import Text from "~/components/atoms/Text";
import Tabs from "~/components/atoms/Tabs";
import { __ } from "@wordpress/i18n";
import DOCS from "~/utils/docs";

const FileBrowser = () => {
    const { edit_data } = useAppSelector((state) => state?.widget_builder);
    const { file_browser } = edit_data?.data?.style || {};

    const dispatch = useAppDispatch();

    const { folder_view, header_options, list_view_table_head } =
        file_browser || {};

    const handleUpdate = (
        key: keyof StyleFileBrowser,
        value: StyleFileBrowser[keyof StyleFileBrowser],
    ) => {
        dispatch(
            updateStyle({
                key: "file_browser",
                value: {
                    ...file_browser!,
                    [key]: value,
                },
            }),
        );
    };

    return (
        <PageContainer
            compact
            style={{ margin: "0 auto" }}
            title={__("Display Settings", "ninja-drive")}
            docLink={DOCS?.MODULE_BUILDER?.style?.link}
        >
            <SettingsField>
                {folder_view && (
                    <BlockStack gap={15}>
                        <Text color="gray-700" size="sm" weight="medium">
                            {__("Default View Style", "ninja-drive")}
                        </Text>

                        <Tabs
                            size="small"
                            rounded="md"
                            tabRounded="sm"
                            tabs={VIEW_STYLE_TABS}
                            active={folder_view || "grid"}
                            onTabClick={(value) =>
                                handleUpdate(
                                    "folder_view",
                                    value as TPreviewStyle,
                                )
                            }
                        />
                    </BlockStack>
                )}

                <Divider width="100%" height="1px" />

                {folder_view === "list" && (
                    <>
                        <BlockStack gap={10}>
                            <Checkbox
                                rounded="sm"
                                title={__("Table Column Names", "ninja-drive")}
                                checked={list_view_table_head?.enable}
                                onChange={() =>
                                    handleUpdate("list_view_table_head", {
                                        ...list_view_table_head!,
                                        enable: !list_view_table_head?.enable,
                                    })
                                }
                            />

                            <Description
                                text={__(
                                    "Enable or disable table column names.",
                                    "ninja-drive",
                                )}
                            />

                            {file_browser?.list_view_table_head?.enable && (
                                <InlineStack
                                    gap={10}
                                    wrap={false}
                                    marginTop={5}
                                >
                                    {[
                                        "name",
                                        "type",
                                        "size",
                                        "updated",
                                        "action",
                                    ]?.map((key) => (
                                        <BlockStack key={key} gap={10}>
                                            <Text
                                                color="gray-700"
                                                size="sm"
                                                weight="medium"
                                                textTransform="capitalize"
                                            >
                                                {`File ${key} column`}
                                            </Text>

                                            <Input
                                                size="small"
                                                background="gray-50"
                                                color="gray-200"
                                                fullWidth={false}
                                                className="flex-1"
                                                value={
                                                    list_view_table_head?.[
                                                        key as
                                                            | "name"
                                                            | "type"
                                                            | "size"
                                                            | "updated"
                                                            | "action"
                                                    ] || ""
                                                }
                                                onChange={(value) =>
                                                    handleUpdate(
                                                        "list_view_table_head",
                                                        {
                                                            ...list_view_table_head!,
                                                            [key]: value as string,
                                                        },
                                                    )
                                                }
                                            />
                                        </BlockStack>
                                    ))}
                                </InlineStack>
                            )}
                        </BlockStack>

                        <Divider width="100%" height="1px" />
                    </>
                )}

                {/* <fs_premium_ui> */}
                {header_options && (
                    <BlockStack gap={20}>
                        <Text color="gray-700" size="sm" weight="medium">
                            {__("Header Options", "ninja-drive")}
                        </Text>

                        <BlockStack gap={15}>
                            {HEADER_OPTIONS?.map(({ key, title }, index) => (
                                <Checkbox
                                    key={key ?? index}
                                    isPro={true}
                                    rounded="sm"
                                    title={title}
                                    checked={header_options?.[key]}
                                    onChange={() => {
                                        if (!toBoolean(pnpnd?.is_pro)) return;

                                        handleUpdate("header_options", {
                                            ...header_options,
                                            [key]: !header_options?.[key],
                                        });
                                    }}
                                />
                            ))}
                        </BlockStack>
                    </BlockStack>
                )}
                {/* </fs_premium_ui> */}
            </SettingsField>
        </PageContainer>
    );
};

export default FileBrowser;

const VIEW_STYLE_TABS: {
    key: "grid" | "list";
    title: string;
    icon: string;
}[] = [
    {
        key: "grid",
        title: __("Grid", "ninja-drive"),
        icon: "grid_view",
    },
    {
        key: "list",
        title: __("List", "ninja-drive"),
        icon: "dehaze",
    },
];

const HEADER_OPTIONS: {
    key: "breadcrumb" | "refresh" | "sorting" | "root_upload";
    title: string;
}[] = [
    {
        key: "breadcrumb",
        title: __("Breadcrumbs", "ninja-drive"),
    },
    {
        key: "refresh",
        title: __("Refresh Button", "ninja-drive"),
    },
    {
        key: "sorting",
        title: __("Sorting", "ninja-drive"),
    },
    {
        key: "root_upload",
        title: __("Enable Root Upload and Create New Folder", "ninja-drive"),
    },
];
