import * as WPElement from "@wordpress/element";
import PreviewMediaPlayer from "./index.tsx";

function renderMediaPlayerShortcode(element) {
    const shortcodeId = element.getAttribute("data-id");

    if (shortcodeId) {
        const data = window[shortcodeId];

        if (data.type !== "media_player") {
            console.error(
                `Element with ID ${shortcodeId} is not a media player shortcode.`,
            );
            return;
        }

        const component = <PreviewMediaPlayer data={data} />;

        if (WPElement.createRoot) {
            WPElement.createRoot(element).render(component);
        } else {
            WPElement.render(component, element);
        }
    } else {
        console.error("No media player shortcode ID found.");
    }
}

export const checkAndRenderElements = () => {
    const mediaPlayerElements = document.querySelectorAll(
        ".pnpnd-media_player",
    );
    if (mediaPlayerElements.length === 0) {
        return;
    }
    mediaPlayerElements.forEach((Element) => {
        if (Element.hasAttribute("data-id")) {
            Element.setAttribute("data-rendered", "true");
            renderMediaPlayerShortcode(Element);
        }
    });
};

checkAndRenderElements();
