import { updateNotification } from "~/store/features/widgetBuilderSlice";
import SettingsField from "~/components/molecules/SettingsField";
import AutoFillInput from "~/components/molecules/AutoFillInput";
import PageContainer from "~/components/molecules/PageContainer";
import { useAppDispatch, useAppSelector } from "~/store/hooks";
import InlineStack from "~/components/molecules/InlineStack";
import Description from "~/components/molecules/Description";
import BlockStack from "~/components/molecules/BlockStack";
import Disabled from "~/components/molecules/Disabled";
import Checkbox from "~/components/atoms/Checkbox";
import Divider from "~/components/atoms/Divider";
import Status from "~/components/atoms/Status";
import { toBoolean } from "~/utils/functions";
import Info from "~/components/atoms/Info";
import Text from "~/components/atoms/Text";
import { __ } from "@wordpress/i18n";
import DOCS from "~/utils/docs";

const NOTIFICATION_TO_PERMISSION: Record<string, string> = {
    new_folder: "new_folder",
    upload: "upload",
    rename: "rename",
    download: "download",
    copy: "copy",
    move: "move",
    share: "share",
    view_share_link: "share",
    delete: "delete",
};

const PERMISSION_LABELS: Record<string, string> = {
    new_folder: __("New Folder", "ninja-drive"),
    upload: __("Upload", "ninja-drive"),
    rename: __("Rename", "ninja-drive"),
    download: __("Download", "ninja-drive"),
    copy: __("Copy", "ninja-drive"),
    move: __("Move", "ninja-drive"),
    share: __("Share", "ninja-drive"),
    delete: __("Delete", "ninja-drive"),
};

const isPermissionEnabled = (
    permissions: Record<string, { enable: boolean }> | undefined,
    notificationKey: string,
): boolean => {
    const permissionKey = NOTIFICATION_TO_PERMISSION[notificationKey];
    if (!permissionKey) return true;
    if (!permissions) return true;
    return permissions?.[permissionKey]?.enable === true;
};

const getPermissionKey = (notificationKey: string): string | undefined => {
    return NOTIFICATION_TO_PERMISSION[notificationKey];
};

const Notifications = () => {
    const { edit_data } = useAppSelector((state) => state?.widget_builder);
    const { notifications } = edit_data?.data || {};
    const { permissions } = edit_data?.data || {};
    const { enable } = notifications || {};

    const dispatch = useAppDispatch();

    const NOTIFICATION_FIELDS: NotificationFieldType[] = [
        {
            key: "new_folder",
            title: __("New Folder", "ninja-drive"),
            description: __(
                "Send a notification when a new folder is created through this widget.",
                "ninja-drive",
            ),
            enabled: notifications?.new_folder !== undefined,
            disabled: !isPermissionEnabled(permissions, "new_folder"),
        },
        {
            key: "upload",
            title: __("Upload", "ninja-drive"),
            description: __(
                "Send a notification when files are uploaded through this widget.",
                "ninja-drive",
            ),
            enabled: notifications?.upload !== undefined,
            disabled:
                edit_data?.type !== "file_uploader" &&
                !isPermissionEnabled(permissions, "upload"),
        },
        {
            key: "rename",
            title: __("Rename", "ninja-drive"),
            description: __(
                "Send a notification when a file or folder is renamed through this widget.",
                "ninja-drive",
            ),
            enabled: notifications?.rename !== undefined,
            disabled: !isPermissionEnabled(permissions, "rename"),
        },
        {
            key: "download",
            title: __("Download", "ninja-drive"),
            description: __(
                "Send a notification when files are downloaded through this widget.",
                "ninja-drive",
            ),
            enabled: notifications?.download !== undefined,
            disabled: !isPermissionEnabled(permissions, "download"),
        },
        {
            key: "copy",
            title: __("Copy", "ninja-drive"),
            description: __(
                "Send a notification when a file or folder is copied through this widget.",
                "ninja-drive",
            ),
            enabled: notifications?.copy !== undefined,
            disabled: !isPermissionEnabled(permissions, "copy"),
        },
        {
            key: "move",
            title: __("Move", "ninja-drive"),
            description: __(
                "Send a notification when a file or folder is moved through this widget.",
                "ninja-drive",
            ),
            enabled: notifications?.move !== undefined,
            disabled: !isPermissionEnabled(permissions, "move"),
        },
        {
            key: "share",
            title: __("Create Share Link", "ninja-drive"),
            description: __(
                "Send a notification when a share link is created through this widget.",
                "ninja-drive",
            ),
            enabled: notifications?.share !== undefined,
            disabled: !isPermissionEnabled(permissions, "share"),
        },
        {
            key: "view_share_link",
            title: __("View Share Link", "ninja-drive"),
            description: __(
                "Send a notification when a share link is viewed through this widget.",
                "ninja-drive",
            ),
            enabled: notifications?.view_share_link !== undefined,
            disabled: !isPermissionEnabled(permissions, "view_share_link"),
        },
        {
            key: "delete",
            title: __("Delete", "ninja-drive"),
            description: __(
                "Send a notification when files are deleted through this widget.",
                "ninja-drive",
            ),
            enabled: notifications?.delete !== undefined,
            disabled: !isPermissionEnabled(permissions, "delete"),
        },
    ];

    return (
        <div>
            <PageContainer
                compact
                style={{
                    margin: "0 auto",
                }}
                title={__("Configure Notification", "ninja-drive")}
                docLink={DOCS?.MODULE_BUILDER?.notifications?.link}
            >
                {/* <fs_premium_only> */}
                <SettingsField>
                    <InlineStack gap={20}>
                        <Text color="gray-700" size="sm" weight="medium">
                            {__("Notification Sent to", "ninja-drive")}
                        </Text>

                        <InlineStack id="enableNotification" gap={10}>
                            {["dashboard", "email"].map((type) => (
                                <InlineStack key={type} gap={10}>
                                    <Checkbox
                                        title={
                                            type === "dashboard"
                                                ? __("Dashboard", "ninja-drive")
                                                : __("Email", "ninja-drive")
                                        }
                                        rounded="sm"
                                        checked={enable?.includes(
                                            type as "dashboard" | "email",
                                        )}
                                        onChange={() => {
                                            if (!toBoolean(pnpnd?.is_pro))
                                                return;

                                            const value = enable?.includes(
                                                type as "dashboard" | "email",
                                            )
                                                ? (enable || []).filter(
                                                      (v) => v !== type,
                                                  )
                                                : [...(enable || []), type];

                                            dispatch(
                                                updateNotification({
                                                    key: "enable",
                                                    value: value as (
                                                        | "dashboard"
                                                        | "email"
                                                    )[],
                                                }),
                                            );
                                        }}
                                    />
                                </InlineStack>
                            ))}
                        </InlineStack>

                        <Status.Pro />
                    </InlineStack>

                    <Divider width="100%" height="1px" />

                    <BlockStack gap={10}>
                        <Text color="gray-700" size="sm" weight="medium">
                            {__("Notification For", "ninja-drive")}
                        </Text>

                        <Description
                            text={__(
                                "Notifications will be sent whenever users trigger the selected actions below.",
                                "ninja-drive",
                            )}
                        />
                    </BlockStack>

                    <Disabled
                        gap={15}
                        depend={
                            !enable?.some((v) =>
                                ["dashboard", "email"].includes(v),
                            )
                        }
                        dependOn="enableNotification"
                    >
                        {NOTIFICATION_FIELDS?.filter(
                            ({ enabled }) => enabled,
                        )?.map(({ key, title, description, disabled }) => {
                            const permissionKey = getPermissionKey(key);
                            const permissionLabel = permissionKey
                                ? PERMISSION_LABELS[permissionKey]
                                : "";

                            return (
                                <InlineStack key={key} gap={10}>
                                    <Checkbox
                                        rounded="sm"
                                        disabled={disabled}
                                        checked={notifications?.[key]}
                                        onChange={() => {
                                            if (!toBoolean(pnpnd?.is_pro))
                                                return;
                                            if (disabled) return;

                                            dispatch(
                                                updateNotification({
                                                    key: key,
                                                    value: !notifications?.[
                                                        key
                                                    ],
                                                }),
                                            );
                                        }}
                                    />

                                    <Text
                                        color="gray-700"
                                        size="sm"
                                        weight="medium"
                                        style={{
                                            cursor: disabled
                                                ? "not-allowed"
                                                : "pointer",
                                            userSelect: "none",
                                            opacity: disabled ? "0.6" : "1",
                                        }}
                                        onClick={() => {
                                            if (!toBoolean(pnpnd?.is_pro))
                                                return;
                                            if (disabled) return;

                                            dispatch(
                                                updateNotification({
                                                    key: key,
                                                    value: !notifications?.[
                                                        key
                                                    ],
                                                }),
                                            );
                                        }}
                                    >
                                        {title}
                                    </Text>

                                    <Info
                                        title={
                                            disabled
                                                ? __(
                                                      "Please enable the",
                                                      "ninja-drive",
                                                  ) +
                                                  ` "${permissionLabel}" ` +
                                                  __(
                                                      "permission first.",
                                                      "ninja-drive",
                                                  )
                                                : description
                                        }
                                    />
                                </InlineStack>
                            );
                        })}
                    </Disabled>
                </SettingsField>
                {/* </fs_premium_only> */}
            </PageContainer>

            <PageContainer
                compact
                style={{ margin: "20px auto 20px" }}
                title={__("Notification Recipients", "ninja-drive")}
                docLink={DOCS?.MODULE_BUILDER?.notifications?.link}
            >
                <SettingsField.SubField
                    background="white"
                    borderStyle="solid"
                    depend={!enable?.includes("email")}
                    dependOn="enableNotification"
                >
                    <AutoFillInput
                        separators={false}
                        defaultSeparator="comma"
                        example={false}
                        value={notifications?.email_recipients || ""}
                        onChange={(value) => {
                            if (!toBoolean(pnpnd?.is_pro)) return;

                            dispatch(
                                updateNotification({
                                    key: "email_recipients",
                                    value: value,
                                }),
                            );
                        }}
                    >
                        <AutoFillInput.Options
                            flex
                            checkbox
                            title={
                                <Text
                                    color="gray-700"
                                    size="sm"
                                    weight="medium"
                                    style={{
                                        marginBottom: "5px",
                                    }}
                                >
                                    {__("Email Recipients", "ninja-drive")}
                                </Text>
                            }
                            options={[
                                {
                                    name: __("Admin Email", "ninja-drive"),
                                    value: "admin_email",
                                },
                                {
                                    name: __(
                                        "Current User Email",
                                        "ninja-drive",
                                    ),
                                    value: "current_user_email",
                                },
                            ]}
                        />
                    </AutoFillInput>

                    <Divider width="100%" height="1px" />

                    <BlockStack gap={10}>
                        <Checkbox
                            title={__(
                                "Skip Current User Notification",
                                "ninja-drive",
                            )}
                            rounded="sm"
                            checked={notifications?.skip_current_user}
                            onChange={() => {
                                if (!toBoolean(pnpnd?.is_pro)) return;

                                dispatch(
                                    updateNotification({
                                        key: "skip_current_user",
                                        value: !notifications?.skip_current_user,
                                    }),
                                );
                            }}
                        />

                        <Description
                            text={__(
                                "Enable to skip the notification for the user that executes the action.",
                                "ninja-drive",
                            )}
                        />
                    </BlockStack>
                </SettingsField.SubField>
            </PageContainer>
        </div>
    );
};

export default Notifications;

type NotificationFieldType = {
    key:
        | "new_folder"
        | "upload"
        | "rename"
        | "download"
        | "copy"
        | "move"
        | "share"
        | "view_share_link"
        | "delete";
    title: string;
    description: string;
    enabled?: boolean;
    disabled?: boolean;
};
