import EmptyState from "~/components/molecules/EmptyState";
import { TimelineView } from "./templates/timeline-view";
import { useFileActions } from "~/hooks/useFileActions";
import { useModuleFiles } from "~/hooks/useModuleFiles";
import { CompactView } from "./templates/compact-view";
import { GalleryView } from "./templates/gallery-view";
import { noFoundIconSvg } from "~/utils/icons";
import { ModuleConfig } from "~/types/widget.types";
import { TableView } from "./templates/table-view";
import { GridView } from "./templates/grid-view";
import { ListView } from "./templates/list-view";
import { checkPermission } from "~/utils/widget";
import { useGallery } from "~/hooks/useGallery";
import ModuleBottom from "../ModuleBottom";
import { File } from "~/types/file.types";
import { __ } from "@wordpress/i18n";

const FileList = ({ data }: { data: ModuleConfig }) => {
    const fileList = data?.data?.style?.file_list;
    const activeView = fileList?.active_view || "list";
    const { loading_type } = data?.data?.style?.files || {};
    const {
        preview,
        download: downloadPermission,
        share: sharePermission,
        rename: renamePermission,
        delete: deletePermission,
    } = data?.data?.permissions || {};

    const { openGoogleDrive, share, download, rename, deleteFile } =
        useFileActions();

    const {
        files,
        has_more,
        loadingMore,
        loadMore,
        total_pages,
        loading,
        loadMoreRef,
        queryArgs,
    } = useModuleFiles(data);

    const { viewFile } = useGallery(files, data?.id, {
        permissions: {
            download: checkPermission("download", downloadPermission!),
        },
        securePlayBack: data.data.configuration.advanced.secure_video_playback,
        showThumbnails: preview?.preview_thumbnail,
    });

    const enablePreview = checkPermission("preview", preview!);

    const enableDownload = checkPermission("download", downloadPermission!);

    const permissions = {
        canPreview: enablePreview,
        canDownload: enableDownload,
        canShare: checkPermission("share", sharePermission!),
        canRename: checkPermission("rename", renamePermission!),
        canDelete: checkPermission("delete", deletePermission!),
    };

    const handleActions = (action: string, file: File) => {
        switch (action) {
            case "preview":
                if (enablePreview && preview?.pop_out) {
                    openGoogleDrive(file, data?.id);
                    return;
                }
                enablePreview && preview?.inline && viewFile(file.file_key);
                break;
            case "share":
                share(file, data?.id);
                break;
            case "download":
                enableDownload &&
                    download(file, data?.id, file?.extension || "");
                break;
            case "rename":
                rename(file, queryArgs?.active_folder, data?.id);
                break;
            case "delete":
                deleteFile(
                    [file?.file_key],
                    queryArgs?.active_folder,
                    data?.id,
                );
                break;
            default:
                break;
        }
    };

    const renderView = () => {
        if (!fileList) return null;

        switch (activeView) {
            case "list":
                return (
                    <ListView
                        widget_id={data?.id}
                        files={files}
                        settings={fileList}
                        permissions={permissions}
                        handleActions={handleActions}
                    />
                );

            case "grid":
                return (
                    <GridView
                        widget_id={data?.id}
                        files={files}
                        settings={fileList}
                        permissions={permissions}
                        handleActions={handleActions}
                    />
                );

            case "compact":
                return (
                    <CompactView
                        widget_id={data?.id}
                        files={files}
                        settings={fileList}
                        permissions={permissions}
                        handleActions={handleActions}
                    />
                );

            case "table":
                return (
                    <TableView
                        widget_id={data?.id}
                        files={files}
                        settings={fileList}
                        permissions={permissions}
                        handleActions={handleActions}
                    />
                );

            case "gallery":
                return (
                    <GalleryView
                        widget_id={data?.id}
                        files={files}
                        settings={fileList}
                        permissions={permissions}
                        handleActions={handleActions}
                    />
                );

            case "timeline":
                return (
                    <TimelineView
                        widget_id={data?.id}
                        files={files}
                        settings={fileList}
                        permissions={permissions}
                        handleActions={handleActions}
                    />
                );

            default:
                return (
                    <ListView
                        widget_id={data?.id}
                        files={files}
                        settings={fileList}
                        permissions={permissions}
                        handleActions={handleActions}
                    />
                );
        }
    };

    if (!files.length && !loading)
        return (
            <EmptyState
                icon={<img src={noFoundIconSvg} alt="" style={{ width: "200px", height: "200px" }} />}
                title={__("No files found", "ninja-drive")}
            />
        );

    return (
        <>
            {renderView()}

            <ModuleBottom
                fileLoadingType={loading_type}
                has_more={has_more}
                loadMore={loadMore}
                total_pages={total_pages}
                current_page={queryArgs?.page || 1}
                isLoading={loading || loadingMore}
                loadMoreFileRef={loadMoreRef}
            />
        </>
    );
};

export default FileList;
