import SkeletonLoader from "~/components/molecules/SkeletonLoader";
import InlineStack from "~/components/molecules/InlineStack";
import BlockStack from "~/components/molecules/BlockStack";
import { GridItemProps } from "./MediaPlayer.type";
import { formatTime } from "~/utils/functions";
import { useMediaPlayer } from "./MediaPlayer";
import Avatar from "~/components/atoms/Avatar";
import { formatFileSize } from "~/utils/file";
import Icon from "~/components/atoms/Icon";
import Text from "~/components/atoms/Text";
import { isAudio } from "~/utils/file";
import clsx from "clsx";

const GridItem = ({ index, media }: GridItemProps) => {
    const {
        mediaAdvanced,
        download,
        handleDownload,
        currentTrack,
        handleTrackChange,
        widget_id,
    } = useMediaPlayer();

    const { name, size, thumbnail_data } = media;

    const { show_number_prefix, show_thumbnail } = mediaAdvanced || {};

    const _isAudio = isAudio(media.extension || "");

    const active = currentTrack === index;

    return (
        <BlockStack
            style={{
                minWidth: 0,
            }}
            className={clsx(
                "pnpnd-media__info-list-grid-item",
                active && "pnpnd-media__info-list-grid-item--active",
            )}
            onClick={() => handleTrackChange(index)}
        >
            {show_number_prefix && (
                <Text
                    color="white"
                    className="pnpnd-media__info-list-grid-item-index"
                >
                    {index + 1}
                </Text>
            )}

            {show_thumbnail && (
                <Avatar
                    src={
                        thumbnail_data
                            ? PNPNDHelper.getUrl(
                                  "thumbnail",
                                  thumbnail_data.file_key,
                                  thumbnail_data.base_name,
                                  widget_id,
                                  "md",
                                  thumbnail_data.extension,
                              )
                            : PNPNDHelper.getUrl(
                                  "thumbnail",
                                  media.file_key,
                                  media.name,
                                  widget_id,
                                  "md",
                                  media.extension,
                              )
                    }
                    width="100%"
                    height="130px"
                    compact={_isAudio && !thumbnail_data}
                    rounded="none"
                    showSpinner
                    customSpinner={
                        <SkeletonLoader width="100%" height="100%" />
                    }
                />
            )}

            <BlockStack
                gap={3}
                padding={10}
                style={{
                    minWidth: 0,
                    marginRight: download ? "35px" : 0,
                }}
            >
                <Text
                    wrap={false}
                    ellipsis
                    style={{
                        minWidth: 0,
                    }}
                >
                    {name}
                </Text>

                <InlineStack gap={5}>
                    <Text size="xs">{formatFileSize(size)}</Text>

                    <Text size="md">•</Text>

                    <Icon name="schedule" />

                    <Text size="xs">
                        {formatTime(Number(media?.media?.duration) || 0)}
                    </Text>
                </InlineStack>
            </BlockStack>

            {download && (
                <Icon
                    name="download"
                    fontSize="xl"
                    className="pnpnd-media__info-list-grid-item-download"
                    onClick={() => handleDownload(media)}
                />
            )}
        </BlockStack>
    );
};

export default GridItem;
