import { useGetUserListQuery, useGetUserRolesQuery } from "~/store/api/authApi";
import PageContainer from "~/components/molecules/PageContainer";
import { useAppSelector } from "~/store/hooks";
import NewFolder from "./components/NewFolder";
import { Fragment } from "@wordpress/element";
import Download from "./components/Download";
import Preview from "./components/Preview";
import Delete from "./components/Delete";
import Upload from "./components/Upload";
import Rename from "./components/Rename";
import Search from "./components/Search";
import Share from "./components/Share";
import { __ } from "@wordpress/i18n";
import Move from "./components/Move";
import Copy from "./components/Copy";
import DOCS from "~/utils/docs";

const Permissions = () => {
    const { edit_data } = useAppSelector((state) => state?.widget_builder);
    const { data: userList } = useGetUserListQuery({
        hide_current_user: true,
    });
    const { data: userRoles } = useGetUserRolesQuery();

    const {
        new_folder,
        upload,
        preview,
        rename,
        download,
        copy,
        move,
        share,
        search,
        delete: deletePermission,
    } = edit_data?.data?.permissions || {};

    const rolesOptions =
        userRoles?.data?.roles.map((user) => ({
            name: user?.role_name,
            value: user?.role_key,
        })) || [];

    const usersOptions =
        userList?.data?.users?.map((user) => ({
            name: user?.user_login,
            value: user?.user_login,
        })) || [];

    const sharedProps = {
        rolesOptions,
        usersOptions,
    };

    const permissionComponents = [
        {
            key: "permissionNewFolder",
            component: <NewFolder {...sharedProps} />,
            isShow: new_folder,
        },
        {
            key: "permissionUpload",
            component: <Upload {...sharedProps} />,
            isShow: upload,
        },
        {
            key: "permissionPreview",
            component: <Preview {...sharedProps} />,
            isShow: preview,
        },
        {
            key: "permissionRename",
            component: <Rename {...sharedProps} />,
            isShow: rename,
        },
        {
            key: "permissionDownload",
            component: <Download {...sharedProps} />,
            isShow: download,
        },
        {
            key: "permissionCopy",
            component: <Copy {...sharedProps} />,
            isShow: copy,
        },
        {
            key: "permissionMove",
            component: <Move {...sharedProps} />,
            isShow: move,
        },
        {
            key: "permissionShare",
            component: <Share {...sharedProps} />,
            isShow: share,
        },
        {
            key: "permissionSearch",
            component: <Search {...sharedProps} />,
            isShow: search,
        },
        {
            key: "permissionDelete",
            component: <Delete {...sharedProps} />,
            isShow: deletePermission,
        },
    ];

    const allPermissionsDisabled = permissionComponents.every(
        ({ isShow }) => !isShow,
    );

    return (
        <>
            {!allPermissionsDisabled && (
                <PageContainer
                    compact
                    style={{ margin: "0 auto" }}
                    title={__("Permissions", "ninja-drive")}
                    docLink={DOCS?.MODULE_BUILDER?.permissions?.link}
                >
                    {permissionComponents
                        .filter(({ isShow }) => isShow)
                        .map(({ key, component }) => (
                            <Fragment key={key}>{component}</Fragment>
                        ))}
                </PageContainer>
            )}
        </>
    );
};

export default Permissions;
