import { getFileType } from "~/utils/file";
import { File } from "~/types/file.types";

interface FileIconProps {
    file: File;
    size?: "sm" | "md" | "lg";
    widget_id: string;
}

export function FileIcon({ file, size = "md", widget_id }: FileIconProps) {
    const type = getFileType(file);

    const thumbnail = PNPNDHelper.getUrl(
        "thumbnail",
        file.file_key,
        file.name,
        widget_id,
        "md",
        file.extension,
    );

    return (
        <div className={`pnpnd-file-icon pnpnd-file-icon--${size} pnpnd-file-icon--${type}`}>
            <img src={thumbnail} alt={file.name} />
        </div>
    );
}

export function FileIconInline({
    file,
    widget_id,
}: {
    file: File;
    widget_id: string;
}) {
    const type = getFileType(file);

    const thumbnail = PNPNDHelper.getUrl(
        "thumbnail",
        file.file_key,
        file.name,
        widget_id,
        "md",
        file.extension,
    );

    return (
        <div className={`pnpnd-file-compact__icon pnpnd-file-icon--${type}`}>
            <img src={thumbnail} alt={file.name} />
        </div>
    );
}
