import { FileActions } from "../file-actions";
import { formatFileSize } from "~/utils/file";
import { timeAgo } from "~/utils/functions";
import { TemplateProps } from "../types";
import { FileIcon } from "../file-icon";

export function GridView({
    files,
    settings,
    permissions,
    handleActions,
    widget_id,
}: TemplateProps) {
    const { date, size, actions, thumbnail } = settings.list_display || {};

    return (
        <div className="pnpnd-file-grid">
            {files.map((file) => (
                <div
                    key={file.file_key}
                    className="pnpnd-file-grid__item"
                    title={file.additional_data?.base_name}
                    onClick={() => handleActions("preview", file)}
                >
                    {thumbnail.enable && (
                        <div className="pnpnd-file-grid__icon">
                            <FileIcon
                                widget_id={widget_id}
                                file={file}
                                size="lg"
                            />
                        </div>
                    )}

                    <div className="pnpnd-file-grid__info">
                        <div className="pnpnd-file-grid__name">
                            {file.additional_data?.base_name}
                        </div>
                        {size.enable && (
                            <div className="pnpnd-file-grid__meta">
                                {formatFileSize(file.size || 0)}
                            </div>
                        )}
                    </div>

                    {(date.enable || actions.enable) && (
                        <div className="pnpnd-file-grid__footer">
                            {date.enable ? (
                                <span className="pnpnd-file-grid__date">
                                    {timeAgo(
                                        file.additional_data?.last_edited || "",
                                    )}
                                </span>
                            ) : (
                                <span className="pnpnd-file-grid__date"></span>
                            )}

                            {actions.enable && (
                                <FileActions
                                    actionExecuter={(action) =>
                                        handleActions(action, file)
                                    }
                                    compact
                                    permissions={permissions}
                                />
                            )}
                        </div>
                    )}
                </div>
            ))}
        </div>
    );
}
