import SkeletonLoader from "~/components/molecules/SkeletonLoader";
import { useLocalStorage } from "~/hooks/useLocalStorage";
import { getDownloadUrl } from "~/utils/functions";
import useDevice from "~/hooks/useDevice";
import { File } from "~/types/file.types";
import MediaFooter from "./MediaFooter";
import { isAudio } from "~/utils/file";
import { __ } from "@wordpress/i18n";
import List from "./List";
import clsx from "clsx";
import {
    createContext,
    useContext,
    useEffect,
    useRef,
    useState,
} from "@wordpress/element";
import {
    MediaPlayerContextType,
    MediaPlayerProps,
    MediaRatioKey,
} from "./MediaPlayer.type";

const MediaPlayerContext = createContext<MediaPlayerContextType | undefined>(
    undefined,
);

export const useMediaPlayer = () => {
    const context = useContext(MediaPlayerContext);

    if (!context) throw new Error("Media Player context missing");

    return context;
};

const MediaPlayer = ({
    data,
    files,
    has_more,
    loadingMore,
    loadMore,
    total_pages,
    loading,
    loadMoreRef,
    queryArgs,
}: MediaPlayerProps) => {
    const isSecurePlaybackEnabled =
        data?.data?.configuration?.advanced?.secure_video_playback;
    const download = data?.data?.permissions?.download?.enable;

    const widget_id = data?.id;

    const mediaAdvanced = data?.data?.style?.media_player;
    const playerRef = useRef<HTMLDivElement>(null);
    const playerInstanceRef = useRef<any>(null);
    const [currentTrack, setCurrentTrack] = useState(0);
    const [autoAdvance, setAutoAdvance] = useState(true);
    const [iframeLoading, setIframeLoading] = useState(true);

    const [showList, setShowList] = useState<boolean>(
        mediaAdvanced?.show_and_hide_playlist || false,
    );
    const [position, setPosition] = useLocalStorage<
        "left" | "right" | "bottom"
    >(
        `pnpnd_media_player_position_${widget_id}`,
        mediaAdvanced?.playlist_position || "left",
    );
    const [listOpen, setListOpen] = useState<boolean>(
        mediaAdvanced?.opened_playlist || false,
    );
    const [listHeight, setListHeight] = useState<number | null>(null);
    const [view, setView] = useLocalStorage<"list" | "grid">(
        `pnpnd_media_player_view_${widget_id}`,
        mediaAdvanced?.playlist_layout || "list",
    );
    const [columns, setColumns] = useLocalStorage<1 | 2 | 3>(
        `pnpnd_media_player_columns_${widget_id}`,
        mediaAdvanced?.columns || 1,
    );
    const [hasScroll, setHasScroll] = useState(false);
    const mediaRef = useRef<HTMLDivElement>(null);
    const listRef = useRef<HTMLDivElement>(null);
    const device = useDevice();

    const ratioMap: Record<MediaRatioKey, number> = {
        "16/9": (9 / 16) * 100,
        "4/3": (3 / 4) * 100,
        "3/2": (2 / 3) * 100,
        "2/1": (1 / 2) * 100,
        "1/1": 100,
        "21/9": (9 / 21) * 100,
        "9/16": (16 / 9) * 100,
    };

    const mediaRatio: MediaRatioKey =
        (mediaAdvanced?.video_ratio as MediaRatioKey) || "16/9";

    const ratio = ratioMap[mediaRatio];

    useEffect(() => {
        if (device === "mobile") {
            setPosition("bottom");
        } else if (device === "tablet") {
            setPosition(
                mediaAdvanced?.playlist_position === "bottom"
                    ? "bottom"
                    : mediaAdvanced?.playlist_position || "left",
            );
        }
    }, [device, mediaAdvanced]);

    useEffect(() => {
        const el = mediaRef.current;
        if (!el) return;

        const update = () => setListHeight(el.offsetHeight);

        update();
        const observer = new ResizeObserver(update);
        observer.observe(el);

        return () => observer.disconnect();
    }, []);

    useEffect(() => {
        if (!isSecurePlaybackEnabled) return;
        if (playerRef.current) {
            playerInstanceRef.current = new (window as any).PNPlayer(
                playerRef.current,
            );
            playerRef.current.addEventListener("mediaended", handleMediaEnded);
        }

        return () => {
            if (playerInstanceRef.current) {
                playerInstanceRef.current.destroy();
            }
            if (playerRef.current) {
                playerRef.current.removeEventListener(
                    "mediaended",
                    handleMediaEnded,
                );
            }
        };
    }, [currentTrack]);

    const handleMediaEnded = () => {
        if (autoAdvance && currentTrack < files.length - 1) {
            handleTrackChange(currentTrack + 1);
        }
    };

    const handleTrackChange = (index: number) => {
        if (!files[index]) return;

        const track = files[index];

        const src = PNPNDHelper.getUrl(
            "preview",
            track?.file_key,
            track?.name,
            widget_id,
            undefined,
            track?.extension,
        );

        const type = isAudio(track?.mime_type) ? "audio" : "video";

        const poster = track?.thumbnail_data
            ? PNPNDHelper.getUrl(
                  "thumbnail",
                  track?.thumbnail_data?.file_key,
                  track?.thumbnail_data?.name,
                  widget_id,
                  "5xl",
                  track?.thumbnail_data?.extension,
              )
            : PNPNDHelper.getUrl(
                  "thumbnail",
                  track?.file_key,
                  track?.name,
                  widget_id,
                  "5xl",
                  track?.extension,
              );

        setCurrentTrack(index);
        if (!isSecurePlaybackEnabled) return;
        playerInstanceRef.current.loadSource(
            src,
            type,
            poster,
            isAudio(track?.mime_type) && !track?.thumbnail_data
                ? "auto"
                : "cover",
        );
    };

    const handleNext = () => {
        const nextIndex = (currentTrack + 1) % files.length;

        handleTrackChange(nextIndex);
    };

    const handlePrevious = () => {
        const prevIndex =
            currentTrack - 1 < 0 ? files.length - 1 : currentTrack - 1;
        handleTrackChange(prevIndex);
    };

    useEffect(() => {
        const el = listRef.current;
        if (!el) return;

        const handleScroll = () => {
            const atBottom =
                Math.ceil(el.scrollTop + el.clientHeight) >= el.scrollHeight;
            setHasScroll(!atBottom);
        };

        handleScroll();
        el.addEventListener("scroll", handleScroll);

        return () => el.removeEventListener("scroll", handleScroll);
    }, [listOpen, listHeight]);

    const handleDownload = (file: File) => {
        const url = getDownloadUrl(file, widget_id);

        const link = document.createElement("a");
        link.href = url;
        link.download = file?.name;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const activeMedia = files[currentTrack];

    const poster = activeMedia?.thumbnail_data
        ? PNPNDHelper.getUrl(
              "thumbnail",
              activeMedia?.thumbnail_data?.file_key,
              activeMedia?.thumbnail_data?.name,
              widget_id,
              "5xl",
              activeMedia?.thumbnail_data?.extension,
          )
        : PNPNDHelper.getUrl(
              "thumbnail",
              activeMedia?.file_key,
              activeMedia?.name,
              widget_id,
              "5xl",
              activeMedia?.extension,
          );

    return (
        <MediaPlayerContext.Provider
            value={{
                data,
                widget_id,
                files,
                mediaAdvanced,
                download,
                position,
                setPosition,
                showList,
                setShowList,
                view,
                setView,
                columns,
                setColumns,
                listOpen,
                setListOpen,
                listHeight,
                hasScroll,
                listRef,
                handleDownload,
                handleNext,
                handlePrevious,
                currentTrack,
                handleTrackChange,
                has_more,
                loadingMore,
                loadMore,
                total_pages,
                loading,
                loadMoreRef,
                queryArgs,
            }}
        >
            <div
                className={clsx("pnpnd-media", `pnpnd-media--${position}`)}
                onContextMenu={(e) => e.preventDefault()}
            >
                <div ref={mediaRef} className="pnpnd-media__media">
                    <div
                        ref={playerRef}
                        className="pnpnd-media__media-content"
                        style={{ aspectRatio: mediaRatio }}
                    >
                        {isSecurePlaybackEnabled ? (
                            <video poster={poster}>
                                <source
                                    src={PNPNDHelper.getUrl(
                                        "preview",
                                        files[currentTrack]?.file_key,
                                        files[currentTrack]?.name,
                                        widget_id,
                                        undefined,
                                        files[currentTrack]?.extension,
                                    )}
                                    type="video/mp4"
                                />

                                {__(
                                    "Your browser does not support the video tag.",
                                    "ninja-drive",
                                )}
                            </video>
                        ) : (
                            <>
                                {iframeLoading && (
                                    <SkeletonLoader
                                        width="100%"
                                        height="100%"
                                        style={{
                                            position: "absolute",
                                            inset: 0,
                                            zIndex: 2,
                                        }}
                                    />
                                )}

                                <iframe
                                    src={PNPNDHelper.getUrl(
                                        "preview",
                                        files[currentTrack]?.file_key,
                                        files[currentTrack]?.name,
                                        widget_id,
                                        undefined,
                                        files[currentTrack]?.extension,
                                    )}
                                    style={{
                                        width: "100%",
                                        height: "100%",
                                        borderRadius: "12px",
                                    }}
                                    onLoad={() => setIframeLoading(false)}
                                />
                            </>
                        )}
                    </div>

                    {mediaAdvanced?.show_next_previous && <MediaFooter />}
                </div>

                {showList && <List />}
            </div>
        </MediaPlayerContext.Provider>
    );
};

export default MediaPlayer;
