import BasePermissions from "./BasePermissions";
import { useAppSelector } from "~/store/hooks";
import { __ } from "@wordpress/i18n";

const Move = ({
    rolesOptions,
    usersOptions,
}: {
    rolesOptions: { name: string; value: string }[];
    usersOptions: { name: string; value: string }[];
}) => {
    const { edit_data } = useAppSelector((state) => state?.widget_builder);
    const move = edit_data?.data?.permissions?.move;

    return (
        <BasePermissions
            enable={move?.enable || false}
            enableTitle={__("Move", "ninja-drive")}
            enableDescription={__(
                "Allow users to move files and folders.",
                "ninja-drive",
            )}
            filterDescription={__(
                "Select users & roles who can move files and folders.",
                "ninja-drive",
            )}
            selectedAccessType={move?.user_access || "everyone"}
            selectedUserType={move?.logged_in_user_type || "users"}
            saveBaseKey="move"
            rolesOptions={rolesOptions}
            usersOptions={usersOptions}
            selectedRolesOrUsers={move?.display_for || []}
        />
    );
};

export default Move;
