import { formatFileSize } from "~/utils/file";
import { FileActions } from "../file-actions";
import { timeAgo } from "~/utils/functions";
import { File } from "~/types/file.types";
import { TemplateProps } from "../types";
import { FileIcon } from "../file-icon";

function getUserFriendlyGroup(dateString: string) {
    const now = new Date();
    const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    const fileDate = new Date(dateString);

    if (isNaN(fileDate.getTime())) return "Older";

    const fileDay = new Date(
        fileDate.getFullYear(),
        fileDate.getMonth(),
        fileDate.getDate(),
    );

    const diffDays = Math.floor(
        (today.getTime() - fileDay.getTime()) / (1000 * 60 * 60 * 24),
    );

    const currentYear = today.getFullYear();
    const fileYear = fileDay.getFullYear();

    // 🔥 Recent ranges
    if (diffDays === 0) return "Today";
    if (diffDays === 1) return "Yesterday";
    if (diffDays <= 7) return "This Week";
    if (diffDays <= 14) return "Last Week";
    if (diffDays <= 30) return "Earlier This Month";

    // 🔥 Year-based grouping
    if (fileYear === currentYear) {
        return "Earlier This Year";
    }

    return fileYear.toString();
}

function groupByDate(files: File[]) {
    const recentOrder = [
        "Today",
        "Yesterday",
        "This Week",
        "Last Week",
        "Earlier This Month",
        "Earlier This Year",
    ];

    const groups: Record<string, File[]> = {};

    files.forEach((file) => {
        const key = file.additional_data?.last_edited
            ? getUserFriendlyGroup(file.additional_data.last_edited)
            : "Older";

        (groups[key] ||= []).push(file);
    });

    // Sort years descending
    const years = Object.keys(groups)
        .filter((k) => /^\d{4}$/.test(k))
        .sort((a, b) => Number(b) - Number(a));

    return [
        ...recentOrder
            .filter((k) => groups[k]?.length)
            .map((k) => [k, groups[k]] as const),
        ...years.map((y) => [y, groups[y]] as const),
        ...(groups["Older"] ? [["Older", groups["Older"]] as const] : []),
    ];
}

export function TimelineView({
    files,
    settings,
    permissions,
    handleActions,
    widget_id,
}: TemplateProps) {
    const groupedFiles = groupByDate(files);

    const {
        actions,
        date: showDate,
        extension,
        size,
        thumbnail,
    } = settings.list_display || {};

    const hasActionsAvailable =
        permissions.canPreview ||
        permissions.canDownload ||
        permissions.canShare ||
        permissions.canRename ||
        permissions.canDelete;

    return (
        <div className="pnpnd-file-timeline">
            {groupedFiles.map(([date, items]) => (
                <div key={date} className="pnpnd-file-timeline__group">
                    <div className="pnpnd-file-timeline__date">{date}</div>

                    <div className="pnpnd-file-timeline__items">
                        {items.map((file) => (
                            <div
                                key={file.id}
                                className="pnpnd-file-timeline__item"
                                title={file.additional_data?.base_name}
                                onClick={() => handleActions("preview", file)}
                            >
                                <div className="pnpnd-file-timeline__left">
                                    {thumbnail.enable && (
                                        <FileIcon
                                            widget_id={widget_id}
                                            file={file}
                                            size="md"
                                        />
                                    )}

                                    <div className="pnpnd-file-timeline__info">
                                        <div className="pnpnd-file-timeline__name">
                                            {file.additional_data?.base_name}
                                        </div>

                                        <div className="pnpnd-file-timeline__meta">
                                            {size.enable && (
                                                <span>
                                                    {formatFileSize(
                                                        file.size || 0,
                                                    )}
                                                </span>
                                            )}

                                            {extension.enable && (
                                                <span>{file.extension}</span>
                                            )}

                                            {file.additional_data
                                                ?.last_edited &&
                                                showDate.enable && (
                                                    <span className="pnpnd-file-timeline__relative-time">
                                                        {timeAgo(
                                                            file.additional_data
                                                                .last_edited ||
                                                                "",
                                                        )}
                                                    </span>
                                                )}
                                        </div>
                                    </div>
                                </div>

                                {actions.enable && hasActionsAvailable && (
                                    <div className="pnpnd-file-timeline__right">
                                        <FileActions
                                            actionExecuter={(action) =>
                                                handleActions(action, file)
                                            }
                                            permissions={permissions}
                                        />
                                    </div>
                                )}
                            </div>
                        ))}
                    </div>
                </div>
            ))}
        </div>
    );
}
