import { useAppDispatch, useAppSelector } from "~/store/hooks";
import Description from "~/components/molecules/Description";
import BlockStack from "~/components/molecules/BlockStack";
import GridStack from "~/components/molecules/GridStack";
import Checkbox from "~/components/atoms/Checkbox";
import Divider from "~/components/atoms/Divider";
import { MBFilter } from "~/types/widget.types";
import BasePermissions from "./BasePermissions";
import Input from "~/components/atoms/Input";
import Text from "~/components/atoms/Text";
import { __ } from "@wordpress/i18n";
import {
    updateFilter,
    updatePermissions,
} from "~/store/features/widgetBuilderSlice";

const Upload = ({
    rolesOptions,
    usersOptions,
}: {
    rolesOptions: { name: string; value: string }[];
    usersOptions: { name: string; value: string }[];
}) => {
    const { edit_data } = useAppSelector((state) => state?.widget_builder);
    const filter = edit_data?.data?.configuration?.filter;
    const upload = edit_data?.data?.permissions?.upload;

    const dispatch = useAppDispatch();

    const handleUpdate = (
        key: keyof MBFilter,
        value: MBFilter[keyof MBFilter],
    ) => {
        dispatch(
            updateFilter({
                key,
                value,
            }),
        );
    };

    return (
        <BasePermissions
            enable={upload?.enable || false}
            enableTitle={__("Upload", "ninja-drive")}
            enableDescription={__(
                "Allow users to upload files.",
                "ninja-drive",
            )}
            filterDescription={__(
                "Select users & roles who can upload files.",
                "ninja-drive",
            )}
            selectedAccessType={upload?.user_access || "everyone"}
            selectedUserType={upload?.logged_in_user_type || "users"}
            saveBaseKey="upload"
            rolesOptions={rolesOptions}
            usersOptions={usersOptions}
            selectedRolesOrUsers={upload?.display_for || []}
            extraContent={
                <>
                    <BlockStack gap={10}>
                        <Checkbox
                            rounded="sm"
                            title={__("Enable Folder Upload", "ninja-drive")}
                            checked={upload?.folder_upload}
                            onChange={() =>
                                dispatch(
                                    updatePermissions({
                                        key: "upload",
                                        value: {
                                            ...edit_data?.data?.permissions
                                                ?.upload!,
                                            folder_upload:
                                                !upload?.folder_upload,
                                        },
                                    }),
                                )
                            }
                        />

                        <Description
                            text={__(
                                "Allow users to upload folders Select. A folder upload button will be added.",
                                "ninja-drive",
                            )}
                        />
                    </BlockStack>

                    <Divider width="100%" height="1px" />

                    <GridStack columns="auto-fit">
                        <BlockStack gap={10}>
                            <Text color="gray-700" size="sm" weight="medium">
                                {__("Max File Upload", "ninja-drive")}
                            </Text>

                            <Input
                                size="small"
                                type="number"
                                background="gray-50"
                                color="gray-200"
                                value={filter?.upload?.max_files || ""}
                                onChange={(value) => {
                                    if (!filter) return;
                                    handleUpdate("upload", {
                                        ...filter.upload,
                                        max_files: value as number,
                                    });
                                }}
                            />
                        </BlockStack>

                        <BlockStack gap={10}>
                            <Text color="gray-700" size="sm" weight="medium">
                                {__("Max File Size (MB)", "ninja-drive")}
                            </Text>

                            <Input
                                size="small"
                                type="number"
                                background="gray-50"
                                color="gray-200"
                                value={filter?.upload?.max_size || ""}
                                onChange={(value) => {
                                    if (!filter) return;
                                    handleUpdate("upload", {
                                        ...filter.upload,
                                        max_size: value as number,
                                    });
                                }}
                            />
                        </BlockStack>

                        <BlockStack gap={10}>
                            <Text color="gray-700" size="sm" weight="medium">
                                {__("Min File Size (MB)", "ninja-drive")}
                            </Text>

                            <Input
                                size="small"
                                type="number"
                                background="gray-50"
                                color="gray-200"
                                value={filter?.upload?.min_size || ""}
                                onChange={(value) => {
                                    if (!filter) return;
                                    handleUpdate("upload", {
                                        ...filter.upload,
                                        min_size: value as number,
                                    });
                                }}
                            />
                        </BlockStack>
                    </GridStack>

                    <Divider width="100%" height="1px" />
                </>
            }
        />
    );
};

export default Upload;
