import { useEffect, useRef, useState } from "@wordpress/element";
import { __ } from "@wordpress/i18n";

interface FileActionsProps {
    visible?: boolean;
    compact?: boolean;
    permissions?: {
        canPreview: boolean;
        canDownload: boolean;
        canShare: boolean;
        canRename: boolean;
        canDelete: boolean;
    };
    actionExecuter: (action: string) => void;
}

interface ActionItem {
    icon: React.ReactNode;
    label: string;
    action: string;
    danger?: boolean;
}

const actions: ActionItem[] = [
    {
        icon: (
            <svg
                xmlns="http://www.w3.org/2000/svg"
                width={24}
                height={24}
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth={2}
                strokeLinecap="round"
                strokeLinejoin="round"
                className="lucide lucide-eye"
            >
                <path d="M2 12s3-7 10-7 10 7 10 7-3 7-10 7-10-7-10-7Z" />
                <circle cx={12} cy={12} r={3} />
            </svg>
        ),
        label: __("Preview", "ninja-drive"),
        action: "preview",
    },
    {
        icon: (
            <svg
                xmlns="http://www.w3.org/2000/svg"
                width={24}
                height={24}
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth={2}
                strokeLinecap="round"
                strokeLinejoin="round"
                className="lucide lucide-download"
            >
                <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" />
                <polyline points="7 10 12 15 17 10" />
                <line x1={12} x2={12} y1={15} y2={3} />
            </svg>
        ),
        label: __("Download", "ninja-drive"),
        action: "download",
    },
    {
        icon: (
            <svg
                xmlns="http://www.w3.org/2000/svg"
                width={24}
                height={24}
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth={2}
                strokeLinecap="round"
                strokeLinejoin="round"
                className="lucide lucide-share2"
            >
                <circle cx={18} cy={5} r={3} />
                <circle cx={6} cy={12} r={3} />
                <circle cx={18} cy={19} r={3} />
                <line x1="8.59" x2="15.42" y1="13.51" y2="17.49" />
                <line x1="15.41" x2="8.59" y1="6.51" y2="10.49" />
            </svg>
        ),
        label: __("Share", "ninja-drive"),
        action: "share",
    },
    {
        icon: (
            <svg
                xmlns="http://www.w3.org/2000/svg"
                width={14}
                height={14}
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth={2}
                strokeLinecap="round"
                strokeLinejoin="round"
                className="lucide lucide-pen-line"
            >
                <path d="M12 20h9" />
                <path d="M16.5 3.5a2.12 2.12 0 0 1 3 3L7 19l-4 1 1-4Z" />
            </svg>
        ),
        label: __("Rename", "ninja-drive"),
        action: "rename",
    },
    {
        icon: (
            <svg
                xmlns="http://www.w3.org/2000/svg"
                width={24}
                height={24}
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth={2}
                strokeLinecap="round"
                strokeLinejoin="round"
                className="lucide lucide-trash2"
            >
                <path d="M3 6h18" />
                <path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6" />
                <path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2" />
                <line x1={10} x2={10} y1={11} y2={17} />
                <line x1={14} x2={14} y1={11} y2={17} />
            </svg>
        ),
        label: __("Delete", "ninja-drive"),
        action: "delete",
        danger: true,
    },
];

export function FileActions({
    visible = false,
    compact = false,
    permissions,
    actionExecuter,
}: FileActionsProps) {
    const [isOpen, setIsOpen] = useState(false);
    const dropdownRef = useRef<HTMLDivElement>(null);
    const buttonRef = useRef<HTMLButtonElement>(null);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (
                dropdownRef.current &&
                !dropdownRef.current.contains(event.target as Node) &&
                !buttonRef.current?.contains(event.target as Node)
            ) {
                setIsOpen(false);
            }
        };

        if (isOpen) {
            document.addEventListener("mousedown", handleClickOutside);
        }

        return () => {
            document.removeEventListener("mousedown", handleClickOutside);
        };
    }, [isOpen]);

    const handleClick = (action: string) => (e: React.MouseEvent) => {
        e.stopPropagation();
        actionExecuter(action);
        setIsOpen(false);
    };

    const toggleDropdown = (e: React.MouseEvent) => {
        e.stopPropagation();
        setIsOpen(!isOpen);
    };

    const { canPreview, canDownload, canShare, canRename, canDelete } =
        permissions || {};

    const filteredActions = actions?.filter((item) => {
        if (!permissions) return true;

        switch (item?.action) {
            case "preview":
                return canPreview;
            case "download":
                return canDownload;
            case "share":
                return canShare;
            case "rename":
                return canRename;
            case "delete":
                return canDelete;
            default:
                return true;
        }
    });

    const filteredNotCompactActions = actions?.slice(3)?.filter((item) => {
        if (!permissions) return true;
        switch (item?.action) {
            case "rename":
                return canRename;
            case "delete":
                return canDelete;
            default:
                return true;
        }
    });

    const hasDropdownActions = canRename || canDelete;
    const hasDirectActions = canPreview || canDownload || canShare;

    if (compact) {
        if (filteredActions.length === 0) return null;

        return (
            <div
                className={`pnpnd-file-actions ${
                    visible ? "pnpnd-file-actions--visible" : ""
                }`}
            >
                <div className="pnpnd-file-actions__dropdown-wrapper">
                    <button
                        ref={buttonRef}
                        className={`pnpnd-file-actions__btn pnpnd-file-actions__btn--menu ${
                            isOpen ? "pnpnd-file-actions__btn--active" : ""
                        }`}
                        onClick={toggleDropdown}
                        title={__("More options", "ninja-drive")}
                    >
                        <svg
                            xmlns="http://www.w3.org/2000/svg"
                            width={24}
                            height={24}
                            viewBox="0 0 24 24"
                            fill="none"
                            stroke="currentColor"
                            strokeWidth={2}
                            strokeLinecap="round"
                            strokeLinejoin="round"
                            className="lucide lucide-ellipsis"
                        >
                            <circle cx={12} cy={12} r={1} />
                            <circle cx={19} cy={12} r={1} />
                            <circle cx={5} cy={12} r={1} />
                        </svg>
                    </button>

                    <div
                        ref={dropdownRef}
                        className={`pnpnd-file-actions__dropdown ${
                            isOpen ? "pnpnd-file-actions__dropdown--open" : ""
                        }`}
                    >
                        <div className="pnpnd-file-actions__dropdown-content">
                            {filteredActions?.map((item, index) => (
                                <button
                                    key={item?.action}
                                    style={{
                                        animationDelay: `${index * 25}ms`,
                                    }}
                                    className={`pnpnd-file-actions__dropdown-item ${
                                        item?.danger
                                            ? "pnpnd-file-actions__dropdown-item--danger"
                                            : ""
                                    }`}
                                    onClick={handleClick(item?.action)}
                                >
                                    <span className="pnpnd-file-actions__dropdown-icon">
                                        {item?.icon}
                                    </span>

                                    <span className="pnpnd-file-actions__dropdown-label">
                                        {item?.label}
                                    </span>
                                </button>
                            ))}
                        </div>
                    </div>
                </div>
            </div>
        );
    }

    if (!hasDirectActions && !hasDropdownActions) return null;

    return (
        <div
            className={`pnpnd-file-actions ${visible ? "pnpnd-file-actions--visible" : ""}`}
        >
            {canPreview && (
                <button
                    className="pnpnd-file-actions__btn"
                    onClick={handleClick("preview")}
                    title={__("Preview", "ninja-drive")}
                >
                    {actions.find((item) => item?.action === "preview")?.icon}
                </button>
            )}

            {canDownload && (
                <button
                    className="pnpnd-file-actions__btn"
                    onClick={handleClick("download")}
                    title={__("Download", "ninja-drive")}
                >
                    {actions.find((item) => item?.action === "download")?.icon}
                </button>
            )}

            {canShare && (
                <button
                    className="pnpnd-file-actions__btn"
                    onClick={handleClick("share")}
                    title={__("Share", "ninja-drive")}
                >
                    {actions.find((item) => item?.action === "share")?.icon}
                </button>
            )}

            {hasDropdownActions && (
                <div className="pnpnd-file-actions__dropdown-wrapper">
                    <button
                        ref={buttonRef}
                        className={`pnpnd-file-actions__btn pnpnd-file-actions__btn--menu ${
                            isOpen ? "pnpnd-file-actions__btn--active" : ""
                        }`}
                        onClick={toggleDropdown}
                        title={__("More options", "ninja-drive")}
                    >
                        <svg
                            xmlns="http://www.w3.org/2000/svg"
                            width={24}
                            height={24}
                            viewBox="0 0 24 24"
                            fill="none"
                            stroke="currentColor"
                            strokeWidth={2}
                            strokeLinecap="round"
                            strokeLinejoin="round"
                            className="lucide lucide-ellipsis"
                        >
                            <circle cx={12} cy={12} r={1} />
                            <circle cx={19} cy={12} r={1} />
                            <circle cx={5} cy={12} r={1} />
                        </svg>
                    </button>

                    <div
                        ref={dropdownRef}
                        className={`pnpnd-file-actions__dropdown ${
                            isOpen ? "pnpnd-file-actions__dropdown--open" : ""
                        }`}
                    >
                        <div className="pnpnd-file-actions__dropdown-content">
                            {filteredNotCompactActions?.map((item, index) => (
                                <button
                                    key={item?.action}
                                    style={{
                                        animationDelay: `${index * 25}ms`,
                                    }}
                                    className={`pnpnd-file-actions__dropdown-item ${
                                        item?.danger
                                            ? "pnpnd-file-actions__dropdown-item--danger"
                                            : ""
                                    }`}
                                    onClick={handleClick(item?.action)}
                                >
                                    <span className="pnpnd-file-actions__dropdown-icon">
                                        {item?.icon}
                                    </span>

                                    <span className="pnpnd-file-actions__dropdown-label">
                                        {item?.label}
                                    </span>
                                </button>
                            ))}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}
