import FilesViews from "~/components/organisms/FilesViews/FilesViews";
import Uploader from "~/components/organisms/Uploader/Uploader";
import BlockStack from "~/components/molecules/BlockStack";
import { useEffect, useState } from "@wordpress/element";
import { useModuleFiles } from "~/hooks/useModuleFiles";
import { useFileActions } from "~/hooks/useFileActions";
import UploaderPanel from "./Components/UploaderPanel";
import { File, FileTypes } from "~/types/file.types";
import { ModuleConfig } from "~/types/widget.types";
import Divider from "~/components/atoms/Divider";
import { checkPermission } from "~/utils/widget";
import { useGallery } from "~/hooks/useGallery";
import Card from "~/components/molecules/Card";
import { Topbar } from "./Components/Topbar";
import ModuleBottom from "../ModuleBottom";
import { isFolder } from "~/utils/file";
import { TLayout } from "~/types/ui";
import { __ } from "@wordpress/i18n";

const FileUploader = ({ data }: { data: ModuleConfig }) => {
    const { style } = data?.data;
    const {
        preview: previewPermission,
        rename: renamePermission,
        download: downloadPermission,
        share: sharePermission,
        delete: deletePermission,
    } = data?.data?.permissions || {};

    const { file_keys } = data?.data?.source || {};

    const selectedFolderKey = file_keys?.[0]?.file_key;

    const {
        folder_upload,
        multiple_upload,
        label_text,
        show_box_label,
        upload_immediately,
        show_upload_confirmation,
        confirmation_message,
        upload_preview,
    } = data?.data?.style?.file_uploader || {};

    const { loading_type } = data?.data?.style?.files || {};

    const { include, all, ignore } =
        data?.data?.configuration?.filter?.extension || {};

    const { max_files, max_size, min_size } =
        data?.data?.configuration?.filter?.upload || {};

    const [layout, setLayout] = useState<TLayout>(
        upload_preview?.preview_style || "grid",
    );

    const [showUploader, setShowUploader] = useState(false);
    const [isFormUploader, setIsFormUploader] = useState(false);

    useEffect(() => {
        const widgetWrapper = document.getElementById(
            `pnpnd-widget-${data?.id}`,
        );
        if (widgetWrapper) {
            const dataFieldName = widgetWrapper.getAttribute("data-field-name");
            if (dataFieldName) setIsFormUploader(true);
        }
    }, [upload_preview?.preview_style]);

    const {
        files,
        openFolder,
        loading,
        loadMoreRef,
        has_more,
        loadingMore,
        queryArgs,
        setQueryArgs,
        loadMore,
        total_pages,
        breadcrumbs,
    } = useModuleFiles(data);

    const { active_folder, order, order_by } = queryArgs;

    const enablePreview = checkPermission("preview", previewPermission!);

    const enableDownload = checkPermission("download", downloadPermission!);

    const { viewFile } = useGallery(files, data.id, {
        permissions: {
            download: enableDownload,
        },
        securePlayBack: data.data.configuration.advanced.secure_video_playback,
        showThumbnails: previewPermission?.preview_thumbnail,
    });

    const {
        activeFile,
        createFolder,
        deleteFile,
        rename,
        download,
        viewDetails,
        share,
        openGoogleDrive,
    } = useFileActions();

    const fileContextMenuList: {
        id: "preview" | "share" | "rename" | "download" | "delete";
        label: string;
        icon: string;
        fileOnly?: boolean;
        separator?: boolean;
        className?: string;
    }[] = [
        {
            id: "preview",
            label: __("Preview", "ninja-drive"),
            icon: "eye_tracking",
            fileOnly: true,
        },
        {
            id: "share",
            label: __("Share", "ninja-drive"),
            icon: "share",
        },
        {
            id: "rename",
            label: __("Rename", "ninja-drive"),
            icon: "text_select_start",
            separator: true,
        },
        {
            id: "download",
            label: __("Download", "ninja-drive"),
            icon: "cloud_download",
        },
        {
            id: "delete",
            label: __("Delete", "ninja-drive"),
            icon: "delete",
            className: "destructive",
        },
    ];

    const filteredFileContextMenuList = fileContextMenuList.filter((menu) => {
        if (menu.id === "preview")
            return (
                checkPermission("preview", previewPermission!) &&
                previewPermission?.inline
            );
        if (menu.id === "rename")
            return checkPermission("rename", renamePermission!);
        if (menu.id === "download")
            return checkPermission("download", downloadPermission!);
        if (menu.id === "delete")
            return checkPermission("delete", deletePermission!);
        if (menu.id === "share")
            return checkPermission("share", sharePermission!);
        return true;
    });

    const triggerSearch = (
        query: string,
        scope: "global" | "folder",
        types: FileTypes[],
    ) => {
        setQueryArgs((prev) => ({
            ...prev,
            search: query,
            search_scope: scope,
            page: 1,
            types,
        }));
    };

    const getKeysFromCookie = (cookieName: string): string[] => {
        try {
            const match = document.cookie
                .split("; ")
                .find((row) => row.startsWith(cookieName + "="));

            if (!match) return [];
            return JSON.parse(decodeURIComponent(match.split("=")[1])) || [];
        } catch {
            return [];
        }
    };

    const setKeysToCookie = (cookieName: string, keys: string[]) => {
        document.cookie = `${cookieName}=${encodeURIComponent(
            JSON.stringify(keys),
        )}; path=/; SameSite=Lax`;
    };

    const getCookieName = () => {
        return `pnpnd_file_uploader_files_${data?.id}`;
    };

    const pushFileKeyToCookie = (cookieName: string, file_key: string) => {
        const existing = getKeysFromCookie(cookieName);

        const updated = existing.includes(file_key)
            ? existing
            : [...existing, file_key];

        setKeysToCookie(cookieName, updated);
    };

    const handleFileUploaded = (file: File) => {
        const cookieName = getCookieName();
        pushFileKeyToCookie(cookieName, file?.file_key);

        const widgetWrapper = document.getElementById(
            `pnpnd-widget-${data?.id}`,
        );
        if (widgetWrapper) {
            const dataFieldName = widgetWrapper.getAttribute("data-field-name");

            if (dataFieldName) {
                const input = document.querySelector(
                    `input[name="${dataFieldName}"]`,
                ) as HTMLInputElement;

                if (input) {
                    const previewUrl = PNPNDHelper.getUrl(
                        "preview",
                        file?.file_key,
                        file?.name,
                        data?.id,
                        undefined,
                        file?.extension,
                    );
                    const newValue = `${file?.name} — (${previewUrl})`;

                    // get current string
                    const currentValue = input?.value.trim();

                    // build pure string
                    const finalValue = currentValue
                        ? `${currentValue}, ${newValue}`
                        : newValue;

                    // set pure string
                    input.value = finalValue;

                    input.dispatchEvent(new Event("change", { bubbles: true }));
                }
            }
        }
    };

    const handleContextMenuClick = (
        id: string,
        file: File,
        extension?: string,
    ) => {
        switch (id) {
            case "preview":
                if (enablePreview && previewPermission?.pop_out) {
                    openGoogleDrive(file, data?.id);
                    return;
                }
                enablePreview &&
                    previewPermission?.inline &&
                    viewFile(file?.file_key);
                break;
            case "share":
                share(file, data?.id);
                break;
            case "rename":
                rename(file, active_folder, data?.id);
                break;
            case "download":
                download(file, data?.id, extension);
                break;
            case "delete":
                deleteFile([file.file_key], active_folder, data?.id);
                break;
            default:
                break;
        }
    };

    const goPrevious = () => {
        if (breadcrumbs.length <= 1) return;

        const updated = breadcrumbs.slice(0, -1);
        const prevFolder = updated[updated.length - 1];

        openFolder(prevFolder.file_key);
    };

    const uploadedFilesKeys = getKeysFromCookie(getCookieName());

    const handleCreateFolder = (activeFolderKey: string, widgetId?: string) => {
        createFolder(activeFolderKey, widgetId, (file: File) => {
            if (file?.file_key) {
                const cookieName = getCookieName();
                pushFileKeyToCookie(cookieName, file.file_key);
            }
        });
    };

    const handleFileClick = (file: File) => {
        if (isFolder(file.extension || "")) {
            openFolder(file.file_key);
        } else {
            if (enablePreview && previewPermission?.pop_out) {
                openGoogleDrive(file, data?.id);
                return;
            }
            enablePreview &&
                previewPermission?.inline &&
                viewFile(file.file_key);
        }
    };

    const handleDoubleClick = (file: File) => {
        if (isFolder(file?.extension || "")) {
            openFolder(file?.file_key);
        } else {
            if (enablePreview && previewPermission?.pop_out) {
                openGoogleDrive(file, data?.id);
                return;
            }
            enablePreview &&
                previewPermission?.inline &&
                viewFile(file.file_key);
        }
    };

    return (
        <>
            {upload_preview?.enable ? (
                <Card
                    background="white"
                    padding={0}
                    className="pnpnd-file-uploader-preview-mode h-full"
                >
                    <FilesViews
                        onFileClick={handleFileClick}
                        onFileDoubleClick={handleDoubleClick}
                        isFileSelecting={false}
                        setIsFileSelecting={() => {}}
                        layout={layout}
                        setLayout={setLayout}
                        files={files}
                        activeFolder={active_folder}
                        breadcrumbs={breadcrumbs}
                        openFolder={openFolder}
                        activeFile={activeFile}
                        setActiveFile={viewDetails}
                        selected_files={[]}
                        setSelectedFiles={() => {}}
                        filesStatus={{ loading, loadingMore, has_more }}
                        showUploader={showUploader}
                        setShowUploader={setShowUploader}
                        sorting={{ order, order_by }}
                        setSorting={(value) =>
                            setQueryArgs({ ...queryArgs, ...value })
                        }
                        list_view_table_head={
                            style?.file_uploader?.upload_preview
                                ?.list_view_table_head
                        }
                    >
                        {upload_preview?.show_header?.enable && (
                            <Card
                                padding={0}
                                style={{
                                    borderTopRightRadius: "12px",
                                    borderTopLeftRadius: "12px",
                                }}
                                rounded="none"
                                background="white"
                                borderStyle="none"
                            >
                                <Topbar
                                    data={data}
                                    layout={layout}
                                    setLayout={setLayout}
                                    triggerSearch={triggerSearch}
                                    loading={loading}
                                    loadingMore={loadingMore}
                                    createFolder={handleCreateFolder}
                                    queryArgs={queryArgs}
                                    setQueryArgs={setQueryArgs}
                                />
                            </Card>
                        )}
                        <Divider />

                        <BlockStack
                            padding={10}
                            style={{
                                height: "100%",
                                overflowY: "scroll",
                                scrollbarWidth: "none",
                                borderRadius: "0 0 12px 12px",
                            }}
                            className="bg-white"
                        >
                            <FilesViews.Files
                                style={{
                                    marginTop: 0,
                                }}
                                notFoundTitle="Upload New File"
                            />

                            <ModuleBottom
                                fileLoadingType={loading_type}
                                has_more={has_more}
                                loadMore={loadMore}
                                total_pages={total_pages}
                                current_page={queryArgs?.page || 1}
                                isLoading={loading || loadingMore}
                                loadMoreFileRef={loadMoreRef}
                            />
                        </BlockStack>

                        <FilesViews.FileContextMenu
                            menuList={filteredFileContextMenuList}
                            onMenuClick={handleContextMenuClick}
                        />

                        {has_more && (
                            <div
                                ref={loadMoreRef}
                                style={{ height: "20px", marginTop: "-20px" }}
                            />
                        )}
                    </FilesViews>

                    <UploaderPanel
                        enableLabel={show_box_label}
                        label={label_text}
                        data={{
                            widget_id: data.id,
                            onFileUpload: handleFileUploaded,
                            setIsUploading: () => {},
                            maxFileSize: Number(max_size) || 0,
                            minFileSize: Number(min_size) || 0,
                            max_files: Number(max_files) || 0,
                            enableFolderUpload: folder_upload,
                            allowMultipleUpload: multiple_upload,
                            uploadImmediately: upload_immediately,
                            showUploadConfirmation: show_upload_confirmation,
                            uploadConfirmationMessage: confirmation_message,
                            activeFolder: queryArgs.active_folder,
                            uploadedFilesKeys,
                            allowAllExtensions: all,
                            allowExtensions: include.join(",") ?? "",
                            allowExceptExtensions: ignore.join(",") ?? "",
                            selectedFolder: selectedFolderKey,
                            isFormUploader: isFormUploader,
                        }}
                    />
                </Card>
            ) : (
                <Uploader
                    fileUploader={true}
                    enableLabel={show_box_label}
                    label={label_text}
                    data={{
                        widget_id: data.id,
                        onFileUpload: handleFileUploaded,
                        setIsUploading: () => {},
                        maxFileSize: Number(max_size) || 0,
                        minFileSize: Number(min_size) || 0,
                        max_files: Number(max_files) || 0,
                        enableFolderUpload: folder_upload,
                        allowMultipleUpload: multiple_upload,
                        uploadImmediately: upload_immediately,
                        activeFolder: queryArgs.active_folder,
                        showUploadConfirmation: show_upload_confirmation,
                        uploadConfirmationMessage: confirmation_message,
                        uploadedFilesKeys,
                        isFormUploader: isFormUploader,
                        allowAllExtensions: all,
                        allowExtensions: include.join(",") ?? "",
                        allowExceptExtensions: ignore.join(",") ?? "",
                        selectedFolder: selectedFolderKey,
                    }}
                />
            )}
        </>
    );
};

export default FileUploader;
