import { FileActions } from "../file-actions";
import { formatFileSize } from "~/utils/file";
import { timeAgo } from "~/utils/functions";
import { TemplateProps } from "../types";
import { FileIcon } from "../file-icon";

export function TableView({
    files,
    settings,
    permissions,
    handleActions,
    widget_id,
}: TemplateProps) {
    const { actions, date, extension, name, size, thumbnail } =
        settings.list_display || {};

    const hasActionsAvailable =
        permissions.canPreview ||
        permissions.canDownload ||
        permissions.canShare ||
        permissions.canRename ||
        permissions.canDelete;

    return (
        <div className="pnpnd-file-table__wrapper">
            <table className="pnpnd-file-table">
                <thead>
                    <tr>
                        <th> {name.text || "Name"}</th>
                        <th> {size.text || "Size"}</th>
                        <th> {extension.text || "Type"}</th>
                        <th> {date.text || "Modified"}</th>
                        {/* <th>Status</th> */}
                        {actions.enable && hasActionsAvailable && (
                            <th> {actions.text || "Actions"}</th>
                        )}
                    </tr>
                </thead>

                <tbody>
                    {files.map((file) => (
                        <tr
                            key={file.id}
                            title={file.additional_data?.base_name}
                            onClick={() => handleActions("preview", file)}
                        >
                            <td>
                                <div className="pnpnd-file-table__name-cell">
                                    {thumbnail.enable && (
                                        <FileIcon
                                            widget_id={widget_id}
                                            file={file}
                                            size="sm"
                                        />
                                    )}
                                    <span>
                                        {file.additional_data?.base_name}
                                    </span>
                                </div>
                            </td>

                            {size.enable && (
                                <td>{formatFileSize(file.size || 0)}</td>
                            )}

                            {extension.enable && <td>{file.extension}</td>}

                            {date.enable && (
                                <td>
                                    {timeAgo(
                                        file.additional_data?.last_edited || "",
                                    )}
                                </td>
                            )}

                            {/* <td>
                                <span
                                    className={`pnpnd-file-table__status pnpnd-file-table__status--${
                                        file.status || "active"
                                    }`}
                                >
                                    {file.status || "Synced"}
                                </span>
                            </td> */}

                            {actions.enable && hasActionsAvailable && (
                                <td>
                                    <FileActions
                                        actionExecuter={(action) =>
                                            handleActions(action, file)
                                        }
                                        permissions={permissions}
                                    />
                                </td>
                            )}
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
}
