import Dropdown from "~/components/molecules/Dropdown";
import { useMediaPlayer } from "./MediaPlayer";
import Icon from "~/components/atoms/Icon";
import {
    LIST_ALIGN_OPTIONS,
    LIST_OPTIONS,
    VIEW_OPTIONS,
} from "./MediaPlayer.type";

const Tools = () => {
    const {
        listOpen,
        position,
        setPosition,
        view,
        setView,
        columns,
        setColumns,
    } = useMediaPlayer();

    return (
        <Dropdown>
            <Dropdown.Trigger disabled={!listOpen}>
                <Icon name="settings" color="primary" fontSize="xl" />
            </Dropdown.Trigger>

            <Dropdown.Content
                position={{
                    top: "110%",
                    left: "50%",
                    transform: "translateX(-50%)",
                }}
            >
                {LIST_OPTIONS?.map((option) => (
                    <Dropdown.MenuItem
                        key={option?.key}
                        isActive={view === option?.key}
                        activeIcon
                        iconPosition="right"
                        activeBg
                        onClick={() => setView(option?.key)}
                    >
                        {option?.name}

                        <Icon name={option?.icon} fontSize="xl" />
                    </Dropdown.MenuItem>
                ))}

                <Dropdown.MenuSeparator />

                {LIST_ALIGN_OPTIONS?.map((align) => (
                    <Dropdown.MenuItem
                        key={align?.key}
                        isActive={position === align?.key}
                        activeIcon
                        iconPosition="right"
                        activeBg
                        onClick={() => setPosition(align?.key)}
                    >
                        {align?.name}

                        <Icon name={align?.icon} fontSize="xl" />
                    </Dropdown.MenuItem>
                ))}

                <Dropdown.MenuSeparator />

                {VIEW_OPTIONS.map((viewOption) => (
                    <Dropdown.MenuItem
                        key={viewOption?.key}
                        isActive={columns === viewOption?.key}
                        activeIcon
                        iconPosition="right"
                        activeBg
                        onClick={() => setColumns(viewOption?.key)}
                    >
                        {viewOption?.name}

                        <Icon name={viewOption?.icon} fontSize="xl" />
                    </Dropdown.MenuItem>
                ))}
            </Dropdown.Content>
        </Dropdown>
    );
};

export default Tools;
