import { formatFileSize, getFileType } from "~/utils/file";
import { TemplateProps } from "../types";
import { FileIcon } from "../file-icon";
import { __ } from "@wordpress/i18n";

export function GalleryView({
    files,
    settings,
    handleActions,
    widget_id,
}: TemplateProps) {
    const { size, thumbnail } = settings.list_display || {};

    return (
        <div className="pnpnd-file-gallery">
            {files.map((file) => (
                <div
                    key={file.file_key}
                    className="pnpnd-file-gallery__item"
                    title={file.additional_data?.base_name}
                    onClick={() => handleActions("preview", file)}
                >
                    <div
                        className={`pnpnd-file-gallery__preview pnpnd-file-icon--${getFileType(
                            file,
                        )}`}
                    >
                        {thumbnail.enable && (
                            <FileIcon
                                widget_id={widget_id}
                                file={file}
                                size="lg"
                            />
                        )}

                        <div className="pnpnd-file-gallery__overlay">
                            <button
                                title={__("Preview", "ninja-drive")}
                                onClick={() => handleActions("preview", file)}
                            >
                                <svg
                                    xmlns="http://www.w3.org/2000/svg"
                                    width={24}
                                    height={24}
                                    viewBox="0 0 24 24"
                                    fill="none"
                                    stroke="currentColor"
                                    strokeWidth={2}
                                    strokeLinecap="round"
                                    strokeLinejoin="round"
                                    className="lucide lucide-eye"
                                >
                                    <path d="M2 12s3-7 10-7 10 7 10 7-3 7-10 7-10-7-10-7Z" />
                                    <circle cx={12} cy={12} r={3} />
                                </svg>
                            </button>
                        </div>
                    </div>

                    <div className="pnpnd-file-gallery__name">
                        {file.additional_data?.base_name}
                    </div>

                    {size.enable && (
                        <div className="pnpnd-file-gallery__size">
                            {formatFileSize(file.size || 0)}
                        </div>
                    )}
                </div>
            ))}
        </div>
    );
}
