import MainLayout from "~/components/templates/MainLayout/MainLayout";
import FilesViews from "~/components/organisms/FilesViews/FilesViews";
import { useFileActions } from "~/hooks/useFileActions";
import { useModuleFiles } from "~/hooks/useModuleFiles";
import { ModuleConfig } from "~/types/widget.types";
import { checkPermission } from "~/utils/widget";
import { useGallery } from "~/hooks/useGallery";
import Search from "../../SearchBox/SearchBox";
import Card from "~/components/molecules/Card";
import { File } from "~/types/file.types";
import { isFolder } from "~/utils/file";
import { __ } from "@wordpress/i18n";

const SearchBox = ({ data }: { data: ModuleConfig }) => {
    const {
        files,
        has_more,
        loadingMore,
        loadMore,
        total_pages,
        loading,
        loadMoreRef,
        queryArgs,
        openFolder,
        setQueryArgs,
    } = useModuleFiles(data);

    const { preview, download: downloadPermission } =
        data?.data?.permissions || {};

    const { download, openGoogleDrive } = useFileActions();

    const enablePreview = checkPermission("preview", preview!);

    const enableDownload = checkPermission("download", downloadPermission!);

    const { viewFile } = useGallery(files, data?.id, {
        permissions: {
            download: enableDownload,
        },
        securePlayBack: data.data.configuration.advanced.secure_video_playback,
        showThumbnails: preview?.preview_thumbnail,
    });

    const { browser_view, search_box_text: placeholder } =
        data?.data?.style?.search_box || {};

    const handleDoubleClick = (file: File) => {
        if (isFolder(file.extension || "")) {
            openFolder(file.file_key);
        } else {
            if (enablePreview && preview?.pop_out) {
                openGoogleDrive(file, data?.id);
                return;
            }
            enablePreview && preview?.inline && viewFile(file?.file_key);
        }
    };

    const handleContextMenuClick = (
        actionId: string,
        file: File,
        extension?: string,
    ) => {
        switch (actionId) {
            case "preview":
                if (enablePreview && preview?.pop_out) {
                    openGoogleDrive(file, data?.id);
                    return;
                }
                enablePreview && preview?.inline && viewFile(file?.file_key);
                break;
            case "download":
                if (enableDownload) {
                    download(file, data?.id, extension);
                }
                break;
            default:
                break;
        }
    };

    return (
        <Card padding={10} background="white">
            <MainLayout>
                <MainLayout.ContentWrapper>
                    <Search
                        isCompact
                        fullWidth
                        placeholder={placeholder}
                        activeFolder={queryArgs?.active_folder}
                        queryArgs={queryArgs}
                        setQueryArgs={setQueryArgs}
                    />

                    <MainLayout.Content>
                        <FilesViews
                            onFileClick={() => {}}
                            onFileDoubleClick={handleDoubleClick}
                            isFileSelecting={false}
                            setIsFileSelecting={() => {}}
                            layout={browser_view || "grid"}
                            setLayout={() => {}}
                            files={files}
                            activeFolder={queryArgs?.active_folder}
                            breadcrumbs={[]}
                            openFolder={openFolder}
                            activeFile={undefined}
                            setActiveFile={() => {}}
                            selected_files={[]}
                            setSelectedFiles={() => {}}
                            filesStatus={{
                                loading,
                                loadingMore,
                                has_more,
                            }}
                            showUploader={false}
                            setShowUploader={() => {}}
                            sorting={{ order: "ASC", order_by: "name" }}
                            setSorting={(value) =>
                                setQueryArgs({ ...queryArgs, ...value })
                            }
                            widget_id={data?.id}
                        >
                            <FilesViews.Files
                                notFoundTitle={__(
                                    "Search your file",
                                    "ninja-drive",
                                )}
                            />

                            <FilesViews.FileContextMenu
                                skipMenus={[
                                    ...(enablePreview
                                        ? []
                                        : ["preview" as const]),
                                    ...(enableDownload
                                        ? []
                                        : ["download" as const]),
                                    "open",
                                    "view-details",
                                    "share",
                                    "downloadLink",
                                    "import",
                                    "copy",
                                    "move",
                                    "rename",
                                    "hide",
                                    "delete",
                                ]}
                                onMenuClick={handleContextMenuClick}
                            />

                            {has_more && (
                                <div
                                    ref={loadMoreRef}
                                    style={{
                                        height: "20px",
                                        marginTop: "-20px",
                                    }}
                                />
                            )}
                        </FilesViews>
                    </MainLayout.Content>
                </MainLayout.ContentWrapper>
            </MainLayout>
        </Card>
    );
};

export default SearchBox;
