import { SORT_BY } from "~/components/organisms/FilesViews/Header";
import IconButton from "~/components/molecules/IconButton";
import BlockStack from "~/components/molecules/BlockStack";
import SelectBox from "~/components/molecules/SelectBox";
import Dropdown from "~/components/molecules/Dropdown";
import { QueryArgs } from "~/types/widget.types";
import Card from "~/components/molecules/Card";
import Text from "~/components/atoms/Text";
import Icon from "~/components/atoms/Icon";
import { OrderBy } from "~/types/Types";

const Actions = ({
    queryArgs,
    setQueryArgs,
}: {
    queryArgs: QueryArgs;
    setQueryArgs: React.Dispatch<React.SetStateAction<QueryArgs>>;
}) => {
    return (
        <Dropdown>
            <Dropdown.Trigger>
                <IconButton variant="outlined" size="small" name="settings" />
            </Dropdown.Trigger>

            <Dropdown.Content
                position={{
                    right: 0,
                    top: "115%",
                }}
                style={{
                    minWidth: "200px",
                }}
            >
                <Dropdown.MenuItem>
                    <BlockStack gap={10}>
                        <Text
                            as="p"
                            size="md"
                            weight="medium"
                            style={{
                                marginBottom: "7px",
                            }}
                        >
                            Appearance
                        </Text>

                        <Text size="sm" weight="medium">
                            Sort By
                        </Text>

                        <SelectBox
                            size="small"
                            options={SORT_BY}
                            value={[queryArgs?.order_by]}
                            onChange={(value) =>
                                setQueryArgs({
                                    ...queryArgs,
                                    order_by: value[0] as OrderBy,
                                    page: 1,
                                })
                            }
                        />

                        <Text size="sm" weight="medium">
                            Order
                        </Text>

                        <Card
                            padding={5}
                            background="primary-extralight"
                            flex
                            align="center"
                            gap={5}
                            rounded="sm"
                        >
                            {ORDER_OPTIONS.map((option) => (
                                <Card
                                    key={option?.key}
                                    padding={6}
                                    rounded="sm"
                                    flex
                                    align="center"
                                    blockAlign="center"
                                    background={
                                        queryArgs.order === option?.key
                                            ? "primary"
                                            : "white"
                                    }
                                    className="cursor-pointer"
                                    onClick={() =>
                                        setQueryArgs({
                                            ...queryArgs,
                                            order: option?.key,
                                            page: 1,
                                        })
                                    }
                                >
                                    <Icon
                                        name={option?.icon}
                                        color={
                                            queryArgs.order === option?.key
                                                ? "white"
                                                : "black"
                                        }
                                    />
                                </Card>
                            ))}
                        </Card>

                        <Text size="sm" weight="medium" wrap={false}>
                            Items per page
                        </Text>

                        <Card
                            padding={5}
                            background="primary-extralight"
                            flex
                            align="center"
                            gap={5}
                            rounded="sm"
                        >
                            {ITEM_PER_PAGE_OPTIONS.map((option) => (
                                <Card
                                    key={option?.count}
                                    padding={6}
                                    rounded="sm"
                                    flex
                                    align="center"
                                    blockAlign="center"
                                    background={
                                        Number(queryArgs.per_page) ===
                                        option?.count
                                            ? "primary"
                                            : "white"
                                    }
                                    style={{
                                        width: "40px",
                                    }}
                                    className="cursor-pointer"
                                    onClick={() =>
                                        setQueryArgs({
                                            ...queryArgs,
                                            per_page: option?.count,
                                            page: 1,
                                        })
                                    }
                                >
                                    <Text
                                        size="sm"
                                        color={
                                            Number(queryArgs.per_page) ===
                                            option?.count
                                                ? "white"
                                                : "black"
                                        }
                                    >
                                        {option?.count}
                                    </Text>
                                </Card>
                            ))}
                        </Card>
                    </BlockStack>
                </Dropdown.MenuItem>
            </Dropdown.Content>
        </Dropdown>
    );
};

export default Actions;

export const ORDER_OPTIONS: {
    key: "ASC" | "DESC";
    icon: string;
}[] = [
    {
        key: "ASC",
        icon: "arrow_warm_up",
    },
    {
        key: "DESC",
        icon: "arrow_cool_down",
    },
];

export const ITEM_PER_PAGE_OPTIONS = [
    {
        count: 10,
    },
    {
        count: 25,
    },
    {
        count: 50,
    },
    {
        count: 100,
    },
];
