import BasePermissions from "./BasePermissions";
import { useAppSelector } from "~/store/hooks";
import { __ } from "@wordpress/i18n";

const Rename = ({
    rolesOptions,
    usersOptions,
}: {
    rolesOptions: { name: string; value: string }[];
    usersOptions: { name: string; value: string }[];
}) => {
    const { edit_data } = useAppSelector((state) => state?.widget_builder);
    const rename = edit_data?.data?.permissions?.rename;

    return (
        <BasePermissions
            enable={rename?.enable || false}
            enableTitle={__("Rename", "ninja-drive")}
            enableDescription={__(
                "Allow users to rename files and folders.",
                "ninja-drive",
            )}
            filterDescription={__(
                "Select users & roles who can rename files and folders.",
                "ninja-drive",
            )}
            selectedAccessType={rename?.user_access || "everyone"}
            selectedUserType={rename?.logged_in_user_type || "users"}
            saveBaseKey="rename"
            rolesOptions={rolesOptions}
            usersOptions={usersOptions}
            selectedRolesOrUsers={rename?.display_for || []}
        />
    );
};

export default Rename;
