import BasePermissions from "./BasePermissions";
import { useAppSelector } from "~/store/hooks";
import { __ } from "@wordpress/i18n";

const Download = ({
    rolesOptions,
    usersOptions,
}: {
    rolesOptions: { name: string; value: string }[];
    usersOptions: { name: string; value: string }[];
}) => {
    const { edit_data } = useAppSelector((state) => state?.widget_builder);
    const download = edit_data?.data?.permissions?.download;

    return (
        <BasePermissions
            enable={download?.enable || false}
            enableTitle={__("Download", "ninja-drive")}
            enableDescription={__(
                "Allow users to download files.",
                "ninja-drive",
            )}
            filterDescription={__(
                "Select users & roles who can download files.",
                "ninja-drive",
            )}
            selectedAccessType={download?.user_access || "everyone"}
            selectedUserType={download?.logged_in_user_type || "users"}
            saveBaseKey="download"
            rolesOptions={rolesOptions}
            usersOptions={usersOptions}
            selectedRolesOrUsers={download?.display_for || []}
        />
    );
};

export default Download;
