import EmptyState from "~/components/molecules/EmptyState";
import { useModuleFiles } from "~/hooks/useModuleFiles";
import { noFoundIconSvg } from "~/utils/icons";
import { ModuleConfig } from "~/types/widget.types";
import MediaPlayer from "./MediaPlayer";
import { __ } from "@wordpress/i18n";

const MediaPlayerWrapper = ({ data }: { data: ModuleConfig }) => {
    const {
        files,
        has_more,
        loadingMore,
        loadMore,
        total_pages,
        loading,
        loadMoreRef,
        queryArgs,
    } = useModuleFiles(data);

    if (!files.length && !loading)
        return (
            <EmptyState
                icon={<img src={noFoundIconSvg} alt="" style={{ width: "200px", height: "200px" }} />}
                title={__("No files found", "ninja-drive")}
            />
        );

    return (
        <MediaPlayer
            data={data}
            files={files}
            has_more={has_more}
            loadingMore={loadingMore}
            loadMore={loadMore}
            total_pages={total_pages}
            loading={loading}
            loadMoreRef={loadMoreRef}
            queryArgs={queryArgs}
        />
    );
};

export default MediaPlayerWrapper;
