import InlineStack from "~/components/molecules/InlineStack";
import { useMediaPlayer } from "./MediaPlayer";
import Button from "~/components/atoms/Button";
import { __ } from "@wordpress/i18n";

const MediaFooter = () => {
    const { files, currentTrack, handlePrevious, handleNext } =
        useMediaPlayer();

    return (
        <InlineStack marginTop={10} gap={10} align="between">
            <Button
                variant="primary"
                size="small"
                rounded="sm"
                startIcon="skip_previous"
                onClick={handlePrevious}
                disabled={currentTrack === 0}
            >
                {__("Prev", "ninja-drive")}
            </Button>

            <Button
                variant="primary"
                size="small"
                rounded="sm"
                startIcon="skip_next"
                onClick={handleNext}
                disabled={currentTrack === files.length - 1}
            >
                {__("Next", "ninja-drive")}
            </Button>
        </InlineStack>
    );
};

export default MediaFooter;
