import BasePermissions from "./BasePermissions";
import { useAppSelector } from "~/store/hooks";
import { __ } from "@wordpress/i18n";

const Share = ({
    rolesOptions,
    usersOptions,
}: {
    rolesOptions: { name: string; value: string }[];
    usersOptions: { name: string; value: string }[];
}) => {
    const { edit_data } = useAppSelector((state) => state?.widget_builder);
    const share = edit_data?.data?.permissions?.share;

    return (
        <BasePermissions
            enable={share?.enable || false}
            enableTitle={__("Share", "ninja-drive")}
            enableDescription={__("Allow users to share files.", "ninja-drive")}
            filterDescription={__(
                "Select users & roles who can share files.",
                "ninja-drive",
            )}
            selectedAccessType={share?.user_access || "everyone"}
            selectedUserType={share?.logged_in_user_type || "users"}
            saveBaseKey="share"
            rolesOptions={rolesOptions}
            usersOptions={usersOptions}
            selectedRolesOrUsers={share?.display_for || []}
        />
    );
};

export default Share;
