import { updatePermissions } from "~/store/features/widgetBuilderSlice";
import { useAppDispatch, useAppSelector } from "~/store/hooks";
import Description from "~/components/molecules/Description";
import BlockStack from "~/components/molecules/BlockStack";
import Checkbox from "~/components/atoms/Checkbox";
import Divider from "~/components/atoms/Divider";
import BasePermissions from "./BasePermissions";
import { __ } from "@wordpress/i18n";

const Delete = ({
    rolesOptions,
    usersOptions,
}: {
    rolesOptions: { name: string; value: string }[];
    usersOptions: { name: string; value: string }[];
}) => {
    const { edit_data } = useAppSelector((state) => state?.widget_builder);
    const deletePermission = edit_data?.data?.permissions?.delete;

    const dispatch = useAppDispatch();

    return (
        <BasePermissions
            enable={deletePermission?.enable || false}
            enableTitle={__("Delete", "ninja-drive")}
            enableDescription={__(
                "Allow users to delete files and folders.",
                "ninja-drive",
            )}
            filterDescription={__(
                "Select users & roles who can delete files and folders.",
                "ninja-drive",
            )}
            selectedAccessType={deletePermission?.user_access || "everyone"}
            selectedUserType={deletePermission?.logged_in_user_type || "users"}
            saveBaseKey="delete"
            rolesOptions={rolesOptions}
            usersOptions={usersOptions}
            selectedRolesOrUsers={deletePermission?.display_for || []}
            extraContent={
                <BlockStack gap={10}>
                    <Checkbox
                        rounded="sm"
                        title={__(
                            "Import to Media Library before deleting",
                            "ninja-drive",
                        )}
                        checked={deletePermission?.is_migrate_attachment}
                        onChange={() =>
                            dispatch(
                                updatePermissions({
                                    key: "delete",
                                    value: {
                                        ...edit_data?.data?.permissions
                                            ?.delete!,
                                        is_migrate_attachment:
                                            !deletePermission?.is_migrate_attachment,
                                    },
                                }),
                            )
                        }
                    />

                    <Description
                        text={__(
                            "Import files to Media Library before deleting them from Google Drive. This ensures that you have a local copy of the files in your WordPress Media Library.",
                            "ninja-drive",
                        )}
                    />

                    <Divider width="100%" height="1px" marginTop={10} />
                </BlockStack>
            }
        />
    );
};

export default Delete;
