import { FileActions } from "../file-actions";
import { formatFileSize } from "~/utils/file";
import { timeAgo } from "~/utils/functions";
import { TemplateProps } from "../types";
import { FileIcon } from "../file-icon";

export function ListView({
    files,
    settings,
    permissions,
    handleActions,
    widget_id,
}: TemplateProps) {
    const { actions, date, extension, name, size, thumbnail } =
        settings.list_display || {};

    const hasActionsAvailable =
        permissions.canPreview ||
        permissions.canDownload ||
        permissions.canShare ||
        permissions.canRename ||
        permissions.canDelete;

    return (
        <div className="pnpnd-file-list">
            <div className="pnpnd-file-list__header">
                <span className="pnpnd-file-list__header-col pnpnd-file-list__header-col--name">
                    {name.text || "Name"}
                </span>

                {size.enable && (
                    <span className="pnpnd-file-list__header-col pnpnd-file-list__header-col--size">
                        {size.text || "Size"}
                    </span>
                )}

                {extension.enable && (
                    <span className="pnpnd-file-list__header-col pnpnd-file-list__header-col--type">
                        {extension.text || "Type"}
                    </span>
                )}

                {date.enable && (
                    <span className="pnpnd-file-list__header-col pnpnd-file-list__header-col--date">
                        {date.text || "Date"}
                    </span>
                )}

                {actions.enable && hasActionsAvailable && (
                    <span className="pnpnd-file-list__header-col pnpnd-file-list__header-col--actions">
                        {actions.text || "Actions"}
                    </span>
                )}
            </div>

            {files.map((file) => (
                <div
                    key={file?.file_key}
                    className="pnpnd-file-list__item"
                    title={file?.additional_data?.base_name}
                    onClick={() => handleActions("preview", file)}
                >
                    <div className="pnpnd-file-list__name">
                        {thumbnail.enable && (
                            <FileIcon
                                widget_id={widget_id}
                                file={file}
                                size="sm"
                            />
                        )}
                        <span>{file?.additional_data?.base_name}</span>
                    </div>

                    {size.enable && (
                        <div className="pnpnd-file-list__size">
                            {formatFileSize(Number(file?.size) || 0)}
                        </div>
                    )}

                    {extension.enable && (
                        <div className="pnpnd-file-list__type">{file?.extension}</div>
                    )}

                    {date.enable && (
                        <div className="pnpnd-file-list__date">
                            {timeAgo(file?.additional_data?.last_edited || "")}
                        </div>
                    )}

                    {actions.enable && hasActionsAvailable && (
                        <div className="pnpnd-file-list__actions">
                            <FileActions
                                actionExecuter={(action) =>
                                    handleActions(action, file)
                                }
                                permissions={permissions}
                            />
                        </div>
                    )}
                </div>
            ))}
        </div>
    );
}
