import SearchBox from "~/components/organisms/SearchBox/SearchBox";
import { ModuleConfig, QueryArgs } from "~/types/widget.types";
import InlineStack from "~/components/molecules/InlineStack";
import IconButton from "~/components/molecules/IconButton";
import { checkPermission } from "~/utils/widget";
import Tooltip from "~/components/atoms/Tooltip";
import { __ } from "@wordpress/i18n";
import Actions from "./Actions";
import FilesViews, {
    useFilesContext,
} from "~/components/organisms/FilesViews/FilesViews";

export const Topbar = ({
    data,
    triggerSearch,
    layout,
    setLayout,
    loading,
    loadingMore,
    createFolder,
    queryArgs,
    setQueryArgs,
}: {
    data: ModuleConfig;
    triggerSearch: any;
    loading: boolean;
    loadingMore: boolean;
    layout: string;
    setLayout: any;
    createFolder: any;
    queryArgs: QueryArgs;
    setQueryArgs: React.Dispatch<React.SetStateAction<QueryArgs>>;
}) => {
    const { activeFolder, showUploader, setShowUploader } = useFilesContext();
    const { style } = data.data;

    const { show_header } = style?.file_uploader?.upload_preview || {};
    const { new_folder, search } = data?.data?.permissions || {};

    const isRootUploadEnabled = style?.file_browser?.header_options.root_upload;

    return (
        <InlineStack
            align={show_header?.breadcrumb ? "between" : "start"}
            padding={10}
            gap={10}
            className="w-full"
        >
            {show_header?.breadcrumb && <FilesViews.Breadcrumbs />}

            <InlineStack
                gap={10}
                wrap={false}
                style={{ width: show_header?.breadcrumb ? "50%" : "100%" }}
                align={show_header?.breadcrumb ? "end" : "between"}
            >
                {checkPermission("search", search!) && (
                    <SearchBox
                        isCompact
                        activeFolder={activeFolder}
                        setQueryArgs={triggerSearch}
                        queryArgs={queryArgs}
                    />
                )}

                <InlineStack gap={10} wrap={false}>
                    {checkPermission("new_folder", new_folder!) && (
                        <Tooltip
                            title={__("New Folder", "ninja-drive")}
                            wrap="no-wrap"
                            placement="top"
                            arrow
                        >
                            <IconButton
                                variant="outlined"
                                size="small"
                                name="create_new_folder"
                                onClick={() =>
                                    createFolder(activeFolder, data?.id)
                                }
                                disabled={
                                    loading ||
                                    loadingMore ||
                                    (activeFolder === "" &&
                                        !isRootUploadEnabled)
                                }
                                title={
                                    activeFolder === "" && !isRootUploadEnabled
                                        ? "Create folder is disabled for root folder"
                                        : ""
                                }
                            />
                        </Tooltip>
                    )}

                    <Tooltip
                        title={layout === "list" ? "Grid View" : "List View"}
                        wrap="no-wrap"
                        placement="top"
                        arrow
                    >
                        <IconButton
                            variant="outlined"
                            size="small"
                            name={layout === "grid" ? "dehaze" : "grid_view"}
                            onClick={() =>
                                setLayout(layout === "grid" ? "list" : "grid")
                            }
                        />
                    </Tooltip>

                    {show_header?.sorting && (
                        <Actions
                            queryArgs={queryArgs}
                            setQueryArgs={setQueryArgs}
                        />
                    )}
                </InlineStack>
            </InlineStack>
        </InlineStack>
    );
};
