import MediaPlayerWrapper from "~/components/organisms/Modules/MediaPlayer__premium_only/MediaPlayerWrapper";
import { ModuleConfig } from "../../types/widget.types";
import FrontendContainer from "../FrontendContainer";
import { useState } from "@wordpress/element";
import FrontendInit from "../FrontendInit";

const PreviewMediaPlayer = ({ data }: { data: ModuleConfig }) => {
    const [widgetData, setWidgetData] = useState<ModuleConfig>(data);

    return (
        <FrontendInit>
            <FrontendContainer data={widgetData} setWidgetData={setWidgetData}>
                <MediaPlayerWrapper data={widgetData} />
            </FrontendContainer>
        </FrontendInit>
    );
};

export default PreviewMediaPlayer;
