import { UploaderProps } from "~/components/organisms/Uploader/Uploader";
import useFileUploader, { IRawFile } from "~/hooks/useFileUploader";
import InlineStack from "~/components/molecules/InlineStack";
import IconButton from "~/components/molecules/IconButton";
import BlockStack from "~/components/molecules/BlockStack";
import { useRef, useState } from "@wordpress/element";
import Button from "~/components/atoms/Button";
import Card from "~/components/molecules/Card";
import { toBoolean } from "~/utils/functions";
import Icon from "~/components/atoms/Icon";
import Text from "~/components/atoms/Text";
import useDevice from "~/hooks/useDevice";
import { __ } from "@wordpress/i18n";
import clsx from "clsx";

const UploaderPanel = ({ data, enableLabel = false, label }: UploaderProps) => {
    const [filter, setFilter] = useState<"all" | "completed" | "failed">("all");

    const device = useDevice();
    const containerRef = useRef<HTMLDivElement>(null);

    const {
        maxFileSize,
        minFileSize,
        enableFolderUpload,
        uploadImmediately = false,
        isFormUploader = false,
        widget_id = "",
    } = data;

    const {
        fileCount,
        statusText,
        uploaderRef,
        files,
        isUploadComplete,
        removeFile,
        startUpload,
        isUploadStarted,
        getFilteredFiles,
        browseFilesId,
        browseFolderId,
    } = useFileUploader(data, containerRef);

    const filteredFiles = getFilteredFiles(filter);
    return (
        <div
            onDragEnter={() =>
                containerRef.current?.classList.add("pnpnd-drag-active")
            }
            onDragLeave={(e) => {
                e.stopPropagation();
                containerRef.current?.classList.remove("pnpnd-drag-active");
            }}
            onDrop={() => containerRef.current?.classList.remove("pnpnd-drag-active")}
            ref={containerRef}
            className="pnpnd-uploader-panel"
        >
            <Card
                background="primary-extralight"
                borderStyle="none"
                rounded="md"
                flex
                direction="col"
                gap={15}
                blockAlign="center"
                className="pnpnd-position-relative"
            >
                <InlineStack
                    align={device === "mobile" ? "center" : "between"}
                    gap={10}
                    wrap={device === "mobile" ? true : false}
                    style={{ width: "100%" }}
                >
                    <BlockStack gap={5}>
                        {enableLabel && label ? (
                            <Text
                                as="span"
                                weight="semibold"
                                align={device === "mobile" ? "center" : "left"}
                            >
                                {label}
                            </Text>
                        ) : (
                            <Text
                                as="span"
                                weight="semibold"
                                align={device === "mobile" ? "center" : "left"}
                            >
                                {__("Add your files", "ninja-drive")}
                            </Text>
                        )}

                        <Text
                            as="span"
                            size="sm"
                            color="gray-500"
                            align={device === "mobile" ? "center" : "left"}
                        >
                            {__("Drag & Drop your files here", "ninja-drive")}
                        </Text>
                    </BlockStack>

                    <BlockStack align="center" inlineAlign="center" gap={5}>
                        <InlineStack gap={10}>
                            <Button
                                variant="primary"
                                startIcon="files"
                                type="button"
                                id={browseFilesId}
                                onMouseOver={() => {
                                    if (
                                        navigator.userAgent.match(
                                            /(iPad|iPhone|iPod)/g,
                                        )
                                    ) {
                                        uploaderRef.current.refresh();
                                    }
                                }}
                            >
                                {__("Files", "ninja-drive")}
                            </Button>

                            {enableFolderUpload && (
                                <Button
                                    variant="primary"
                                    startIcon="folder"
                                    type="button"
                                    id={browseFolderId}
                                    onMouseOver={() => {
                                        if (
                                            navigator.userAgent.match(
                                                /(iPad|iPhone|iPod)/g,
                                            )
                                        ) {
                                            uploaderRef.current.refresh();
                                        }
                                    }}
                                    disabled={!enableFolderUpload}
                                >
                                    {__("Folder", "ninja-drive")}
                                </Button>
                            )}
                        </InlineStack>
                        <InlineStack gap={5}>
                            {!!minFileSize && (
                                <Text as="span" size="xs" color="gray-500">
                                    {__("Min File Size:", "ninja-drive")}{" "}
                                    {minFileSize}MB
                                </Text>
                            )}
                            {!!minFileSize && !!maxFileSize && (
                                <Text as="span" size="xs" color="gray-500">
                                    |
                                </Text>
                            )}
                            {!!maxFileSize && (
                                <Text as="span" size="xs" color="gray-500">
                                    {__("Max File Size:", "ninja-drive")}{" "}
                                    {maxFileSize}MB
                                </Text>
                            )}
                        </InlineStack>
                    </BlockStack>
                </InlineStack>
            </Card>

            {!!files.length && (
                <div className="pnpnd-file-list-wrapper">
                    <BlockStack gap={5}>
                        {enableLabel && label ? (
                            <Text
                                as="span"
                                size="lg"
                                color="black"
                                weight="semibold"
                            >
                                {label}
                            </Text>
                        ) : (
                            <Text
                                as="span"
                                size="lg"
                                color="black"
                                weight="semibold"
                            >
                                {__("Uploads", "ninja-drive")}
                            </Text>
                        )}

                        <InlineStack
                            padding={"5px 0px"}
                            gap={6}
                            style={{
                                marginTop: "5px",
                            }}
                        >
                            <Button
                                variant={
                                    filter === "all" ? "primary" : "outlined"
                                }
                                size="small"
                                onClick={() => setFilter("all")}
                            >
                                {__("All Uploads", "ninja-drive")}
                            </Button>
                            <Button
                                variant={
                                    filter === "completed"
                                        ? "primary"
                                        : "outlined"
                                }
                                size="small"
                                onClick={() => setFilter("completed")}
                            >
                                {__("Completed", "ninja-drive")}
                            </Button>
                            <Button
                                variant={
                                    filter === "failed" ? "primary" : "outlined"
                                }
                                size="small"
                                onClick={() => setFilter("failed")}
                            >
                                {__("Failed", "ninja-drive")}
                            </Button>
                        </InlineStack>
                    </BlockStack>

                    <div className="pnpnd-file-list">
                        {filteredFiles.length === 0 && (
                            <Text
                                as="span"
                                size="sm"
                                color="gray-800"
                                style={{ padding: "10px 0px" }}
                            >
                                {__("No", "ninja-drive")} {filter}{" "}
                                {__("files", "ninja-drive")}
                            </Text>
                        )}
                        {[...new Set(filteredFiles)].map(
                            (file: IRawFile, index) => {
                                const { id, name, size, type, error } = file;
                                const isUploading =
                                    files.find((f) => f.id === file.id)
                                        ?.status === "uploading";
                                const isUploaded =
                                    files.find((f) => f.id === file.id)
                                        ?.status === "done";

                                const isProcessing =
                                    files.find((f) => f.id === file.id)
                                        ?.status === "uploading";
                                const isPaused =
                                    files.find((f) => f.id === file.id)
                                        ?.status === "paused";

                                const itemClasses = clsx(
                                    "pnpnd-file-list-item",
                                    isUploading && "pnpnd-active",
                                    (isUploaded || isProcessing) && "pnpnd-uploaded",
                                );

                                return (
                                    <div
                                        key={id}
                                        className={itemClasses}
                                        id={id}
                                    >
                                        <div className="pnpnd-file-info">
                                            <div className="pnpnd-file-name">
                                                <Text
                                                    as="span"
                                                    size="sm"
                                                    color="gray-800"
                                                    wrap={false}
                                                >
                                                    #{index + 1} {name}
                                                </Text>
                                                <InlineStack gap={5}>
                                                    <Text
                                                        as="span"
                                                        size="xs"
                                                        color="gray-500"
                                                        wrap={false}
                                                    >
                                                        {type.toLocaleUpperCase()}
                                                    </Text>
                                                    <Text
                                                        as="span"
                                                        size="xs"
                                                        color="gray-500"
                                                    >
                                                        •
                                                    </Text>
                                                    <Text
                                                        as="span"
                                                        size="xs"
                                                        color="gray-500"
                                                        wrap={false}
                                                    >
                                                        {plupload.formatSize(
                                                            size,
                                                        )}
                                                    </Text>
                                                    {error && (
                                                        <>
                                                            <Text
                                                                as="span"
                                                                size="xs"
                                                                color="gray-500"
                                                            >
                                                                •
                                                            </Text>
                                                            <Text
                                                                as="span"
                                                                size="xs"
                                                                color="error"
                                                                wrap={false}
                                                            >
                                                                {error}
                                                            </Text>
                                                        </>
                                                    )}
                                                </InlineStack>
                                            </div>

                                            <div className="pnpnd-file-actions">
                                                {isUploaded && (
                                                    <IconButton
                                                        name="check"
                                                        size="extrasmall"
                                                        variant="primary"
                                                    />
                                                )}
                                                {!isUploaded &&
                                                    (isUploading ||
                                                        isProcessing) &&
                                                    !error &&
                                                    !isPaused && (
                                                        <div className="pnpnd-spinner" />
                                                    )}
                                                {!isUploaded &&
                                                    isUploading &&
                                                    !!file.percent && (
                                                        <Text
                                                            as="span"
                                                            size="sm"
                                                            color="black"
                                                        >
                                                            {file.percent}%
                                                        </Text>
                                                    )}
                                                {!isUploaded && (
                                                    <IconButton
                                                        name="close"
                                                        size="microsmall"
                                                        variant="error"
                                                        className="pnpnd-remove-file"
                                                        onClick={() => {
                                                            removeFile(file.id);
                                                        }}
                                                        data-for="remove-file"
                                                    />
                                                )}
                                            </div>
                                            <span
                                                className="pnpnd-file-info-progress"
                                                style={
                                                    {
                                                        "--percentage":
                                                            isUploading
                                                                ? `${file.percent}%`
                                                                : "100%",
                                                    } as React.CSSProperties
                                                }
                                            >
                                                <span className="pnpnd-file-info-progress-bar" />
                                            </span>
                                        </div>
                                    </div>
                                );
                            },
                        )}
                    </div>
                    {fileCount > 0 &&
                        !toBoolean(isFormUploader) &&
                        !toBoolean(uploadImmediately) && (
                            <InlineStack
                                align="center"
                                style={{
                                    marginBottom: "10px",
                                }}
                            >
                                <Button
                                    variant="primary"
                                    size="small"
                                    startIcon="cloud_upload"
                                    onClick={() => startUpload()}
                                >
                                    {isUploadStarted
                                        ? "Uploading Files..."
                                        : "Start Upload"}
                                </Button>
                            </InlineStack>
                        )}
                    <Card background="primary" padding={"10px 20px"}>
                        <InlineStack
                            align={device === "mobile" ? "center" : "between"}
                            gap={10}
                        >
                            <InlineStack gap={10} align="center">
                                {isUploadComplete ? (
                                    <Icon name="cloud_done" color="white" />
                                ) : (
                                    <Icon name="cloud_upload" color="white" />
                                )}
                                <InlineStack
                                    gap={3}
                                    padding={"5px 0px"}
                                    wrap={false}
                                    style={{
                                        minWidth: 0,
                                    }}
                                >
                                    <Text as="span" size="md" color="white">
                                        {fileCount}
                                    </Text>
                                    <Text
                                        as="span"
                                        size="md"
                                        color="white"
                                        wrap={false}
                                        ellipsis
                                        style={{
                                            minWidth: 0,
                                        }}
                                    >
                                        {statusText}
                                    </Text>
                                </InlineStack>
                            </InlineStack>
                            <InlineStack gap={10} align="center">
                                <Button
                                    size="small"
                                    variant="outlined"
                                    startIcon="files"
                                    type="button"
                                    className="pnpnd-uploader-file-select-button"
                                    onMouseOver={() => {
                                        if (
                                            navigator.userAgent.match(
                                                /(iPad|iPhone|iPod)/g,
                                            )
                                        ) {
                                            uploaderRef.current.refresh();
                                        }
                                    }}
                                    onClick={() => {
                                        const browseFilesBtn =
                                            document.getElementById(
                                                browseFilesId,
                                            );
                                        browseFilesBtn?.click();
                                    }}
                                >
                                    {__("Files", "ninja-drive")}
                                </Button>

                                {enableFolderUpload && (
                                    <Button
                                        size="small"
                                        variant="outlined"
                                        startIcon="folder"
                                        type="button"
                                        className="pnpnd-uploader-file-select-button"
                                        onMouseOver={() => {
                                            if (
                                                navigator.userAgent.match(
                                                    /(iPad|iPhone|iPod)/g,
                                                )
                                            ) {
                                                uploaderRef.current.refresh();
                                            }
                                        }}
                                        disabled={!enableFolderUpload}
                                        onClick={() => {
                                            const browseFilesBtn =
                                                document.getElementById(
                                                    browseFolderId,
                                                );
                                            browseFilesBtn?.click();
                                        }}
                                    >
                                        {__("Folder", "ninja-drive")}
                                    </Button>
                                )}
                            </InlineStack>
                        </InlineStack>
                    </Card>
                </div>
            )}
        </div>
    );
};

export default UploaderPanel;
