import * as WPElement from "@wordpress/element";
import PreviewSliderCarousel from "./index.tsx";

function renderSliderCarousel(sliderCarousel) {
    const shortcodeId = sliderCarousel.getAttribute("data-id");

    if (shortcodeId) {
        const data = window[shortcodeId];

        if (data.type !== "slider_carousel") {
            console.error("Invalid slider carousel data");
            return;
        }

        const component = <PreviewSliderCarousel data={data} />;

        if (WPElement.createRoot) {
            WPElement.createRoot(sliderCarousel).render(component);
        } else {
            WPElement.render(component, sliderCarousel);
        }
    }
}

export const checkAndRenderElements = () => {
    const sliderCarousels = document.querySelectorAll(".pnpnd-slider_carousel");
    if (sliderCarousels.length === 0) {
        return;
    }

    if (sliderCarousels.length > 0) {
        sliderCarousels.forEach((sliderCarousel) => {
            if (sliderCarousel.hasAttribute("data-id")) {
                sliderCarousel.setAttribute("data-rendered", "true");
                renderSliderCarousel(sliderCarousel);
            }
        });
    }
};

checkAndRenderElements();
