import InlineStack from "~/components/molecules/InlineStack";
import { useEffect, useState } from "@wordpress/element";
import { useMediaPlayer } from "./MediaPlayer";
import Card from "~/components/molecules/Card";
import ModuleBottom from "../ModuleBottom";
import Text from "~/components/atoms/Text";
import Icon from "~/components/atoms/Icon";
import ListItem from "./ListItem";
import GridItem from "./GridItem";
import Tools from "./Tools";
import clsx from "clsx";

const List = () => {
    const [listHeight, setListHeight] = useState(60);
    const {
        data,
        files,
        mediaAdvanced,
        position,
        view,
        columns,
        listOpen,
        setListOpen,
        listHeight: mediaListHeight,
        hasScroll,
        listRef,
        currentTrack,
        has_more,
        loadMore,
        total_pages,
        queryArgs,
        loading,
        loadingMore,
        loadMoreRef,
    } = useMediaPlayer();

    useEffect(() => {
        if (listOpen) {
            setListHeight(mediaListHeight ?? 60);
        } else {
            setListHeight(60);
        }
    }, [listOpen, mediaListHeight]);

    return (
        <Card
            padding={0}
            background="white"
            style={{
                width:
                    position === "bottom"
                        ? "100%"
                        : view === "list"
                        ? "350px"
                        : columns === 1
                        ? "250px"
                        : columns === 2
                        ? "500px"
                        : "750px",
                height: listOpen
                    ? position === "bottom"
                        ? "auto"
                        : `${listHeight}px`
                    : "60px",
                overflow: "hidden",
                transition: "width height 0.35s ease",
                userSelect: "none",
            }}
            className="pnpnd-media__info"
        >
            <InlineStack
                align="between"
                gap={10}
                wrap={false}
                className="pnpnd-media__info-header"
                onClick={() => setListOpen(!listOpen)}
            >
                <InlineStack
                    gap={10}
                    wrap={false}
                    style={{
                        minWidth: 0,
                    }}
                >
                    <Text
                        size="lg"
                        weight="medium"
                        wrap={false}
                        ellipsis
                        style={{
                            minWidth: 0,
                        }}
                    >
                        {mediaAdvanced?.playlist_title}
                    </Text>

                    <Tools />
                </InlineStack>

                <Icon
                    name="stat_1"
                    fontSize="3xl"
                    fontWeight="medium"
                    className={clsx(
                        listOpen && "pnpnd-media__info-header-icon--open",
                    )}
                />
            </InlineStack>

            <div
                ref={listRef}
                style={{
                    margin: view === "grid" ? "15px 15px 0 15px" : 0,
                    paddingBottom:
                        view === "grid"
                            ? "90px"
                            : position === "bottom"
                            ? 0
                            : "60px",
                    opacity: listOpen ? 1 : 0,
                    transition: "opacity 0.25s ease",
                }}
                className={clsx(
                    "pnpnd-media__info-list",
                    `pnpnd-media__info-list--${view}`,
                    view === "grid" &&
                        position !== "bottom" &&
                        `pnpnd-media__info-list--grid-${columns}`,
                    position === "bottom" &&
                        "pnpnd-media__info-list--grid-bottom",
                )}
            >
                {files.map((media, index) => (
                    <div
                        key={media?.file_key ?? index}
                        style={{
                            minWidth: 0,
                        }}
                    >
                        {view === "list" ? (
                            <ListItem
                                index={index}
                                media={media}
                                maxDigits={String(files?.length).length}
                            />
                        ) : (
                            <GridItem index={index} media={media} />
                        )}

                        <ModuleBottom
                            fileLoadingType={"infinite_scroll"}
                            has_more={has_more}
                            loadMore={loadMore}
                            total_pages={total_pages}
                            current_page={queryArgs?.page || 1}
                            isLoading={loading || loadingMore}
                            loadMoreFileRef={loadMoreRef}
                        />
                    </div>
                ))}
            </div>

            {listOpen && hasScroll && (
                <div className="pnpnd-media__info--layer" />
            )}
        </Card>
    );
};

export default List;
