import { updatePermissions } from "~/store/features/widgetBuilderSlice";
import { useAppDispatch, useAppSelector } from "~/store/hooks";
import InlineStack from "~/components/molecules/InlineStack";
import BlockStack from "~/components/molecules/BlockStack";
import Divider from "~/components/atoms/Divider";
import BasePermissions from "./BasePermissions";
import Radio from "~/components/atoms/Radio";
import Text from "~/components/atoms/Text";
import { __ } from "@wordpress/i18n";

const Search = ({
    rolesOptions,
    usersOptions,
}: {
    rolesOptions: { name: string; value: string }[];
    usersOptions: { name: string; value: string }[];
}) => {
    const { edit_data } = useAppSelector((state) => state?.widget_builder);
    const search = edit_data?.data?.permissions?.search;

    const dispatch = useAppDispatch();

    return (
        <BasePermissions
            enable={search?.enable || false}
            enableTitle={__("Search", "ninja-drive")}
            enableDescription={__(
                "Allow users to search files.",
                "ninja-drive",
            )}
            filterDescription={__(
                "Select users & roles who can search files.",
                "ninja-drive",
            )}
            selectedAccessType={search?.user_access || "everyone"}
            selectedUserType={search?.logged_in_user_type || "users"}
            saveBaseKey="search"
            rolesOptions={rolesOptions}
            usersOptions={usersOptions}
            selectedRolesOrUsers={search?.display_for || []}
            extraContent={
                <BlockStack gap={20}>
                    <InlineStack gap={10}>
                        <Text color="gray-700" size="sm" weight="medium">
                            {__("Default Search Scope", "ninja-drive")}
                        </Text>

                        <InlineStack gap={10}>
                            {["cache", "server"].map((option) => (
                                <Radio
                                    key={option}
                                    title={option}
                                    checked={
                                        search?.search_location?.[
                                            option as "cache" | "server"
                                        ]
                                    }
                                    onChange={() =>
                                        dispatch(
                                            updatePermissions({
                                                key: "search",
                                                value: {
                                                    ...edit_data?.data
                                                        ?.permissions?.search!,
                                                    search_location: {
                                                        cache:
                                                            option === "cache",
                                                        server:
                                                            option === "server",
                                                    },
                                                },
                                            }),
                                        )
                                    }
                                />
                            ))}
                        </InlineStack>
                    </InlineStack>

                    <InlineStack gap={10}>
                        <Text color="gray-700" size="sm" weight="medium">
                            {__("Default Search Location", "ninja-drive")}
                        </Text>

                        <InlineStack gap={10}>
                            {["current", "global"].map((option) => (
                                <Radio
                                    key={option}
                                    title={option}
                                    checked={
                                        search?.search_scope?.[
                                            option as "current" | "global"
                                        ]
                                    }
                                    onChange={() =>
                                        dispatch(
                                            updatePermissions({
                                                key: "search",
                                                value: {
                                                    ...edit_data?.data
                                                        ?.permissions?.search!,
                                                    search_scope: {
                                                        current:
                                                            option ===
                                                            "current",
                                                        global:
                                                            option === "global",
                                                    },
                                                },
                                            }),
                                        )
                                    }
                                />
                            ))}
                        </InlineStack>
                    </InlineStack>

                    <Divider width="100%" height="1px" />
                </BlockStack>
            }
        />
    );
};

export default Search;
