    listOpen: boolean;
    setListOpen: (open: boolean) => void;
    listHeight: number | null;
    hasScroll: boolean;
    listRef: React.RefObject<HTMLDivElement>;
    handleDownload: (file: File) => void;
    currentTrack: number;
    handlePrevious: () => void;
    handleNext: () => void;
    handleTrackChange: (index: number) => void;
    has_more: boolean;
    loadingMore: boolean;
