import SkeletonLoader from "~/components/molecules/SkeletonLoader";
import InlineStack from "~/components/molecules/InlineStack";
import BlockStack from "~/components/molecules/BlockStack";
import { ListItemProps } from "./MediaPlayer.type";
import Avatar from "~/components/atoms/Avatar";
import { formatTime } from "~/utils/functions";
import { useMediaPlayer } from "./MediaPlayer";
import { formatFileSize } from "~/utils/file";
import Text from "~/components/atoms/Text";
import Icon from "~/components/atoms/Icon";
import { isAudio } from "~/utils/file";
import clsx from "clsx";

const ListItem = ({ index, media, maxDigits }: ListItemProps) => {
    const {
        mediaAdvanced,
        download,
        handleDownload,
        handleTrackChange,
        currentTrack,
        widget_id,
    } = useMediaPlayer();

    const { name, size, thumbnail, thumbnail_data } = media;

    const { show_number_prefix, show_thumbnail } = mediaAdvanced || {};

    const _isAudio = isAudio(media.extension || "");

    const active = currentTrack === index;

    const indexWidth = `${maxDigits! * 8 + 16}px`;

    const formatIndex = (i: number) => String(i).padStart(maxDigits!, "0");

    return (
        <InlineStack
            gap={10}
            wrap={false}
            style={{
                minWidth: 0,
            }}
            className={clsx(
                "pnpnd-media__info-list-list-item",
                active && "pnpnd-media__info-list-list-item--active",
            )}
            onClick={() => {
                handleTrackChange(index);
            }}
        >
            {show_number_prefix && (
                <Text
                    style={{
                        width: indexWidth,
                        textAlign: "right",
                        flexShrink: 0,
                    }}
                >
                    {formatIndex(index + 1)}.
                </Text>
            )}

            {show_thumbnail && (
                <Avatar
                    src={
                        thumbnail_data
                            ? PNPNDHelper.getUrl(
                                  "thumbnail",
                                  thumbnail_data.file_key,
                                  thumbnail_data.base_name,
                                  widget_id,
                                  "md",
                                  thumbnail_data.extension,
                              )
                            : PNPNDHelper.getUrl(
                                  "thumbnail",
                                  media.file_key,
                                  media.name,
                                  widget_id,
                                  "md",
                                  media.extension,
                              )
                    }
                    width="80px"
                    height="50px"
                    compact={_isAudio && !thumbnail_data}
                    rounded="sm"
                    showSpinner
                    customSpinner={
                        <SkeletonLoader width="100%" height="100%" />
                    }
                    style={{
                        flexShrink: 0,
                    }}
                    className={clsx(
                        !thumbnail &&
                            "border border-solid border-primary-light rounded-md",
                    )}
                />
            )}

            <BlockStack
                style={{
                    minWidth: 0,
                    marginRight: download ? "35px" : 0,
                }}
            >
                <Text
                    wrap={false}
                    ellipsis
                    style={{
                        minWidth: 0,
                    }}
                >
                    {name}
                </Text>

                <InlineStack gap={5}>
                    <Text size="sm">{formatFileSize(size)}</Text>

                    <Text size="md">•</Text>

                    <Icon name="schedule" />

                    <Text size="sm">
                        {formatTime(Number(media?.media?.duration) || 0)}
                    </Text>
                </InlineStack>
            </BlockStack>

            {download && (
                <Icon
                    name="download"
                    fontSize="xl"
                    className={clsx(
                        "pnpnd-media__info-list-list-item-download",
                    )}
                    onClick={() => handleDownload(media)}
                />
            )}
        </InlineStack>
    );
};

export default ListItem;
