import BasePermissions from "./BasePermissions";
import { useAppSelector } from "~/store/hooks";
import { __ } from "@wordpress/i18n";

const NewFolder = ({
    rolesOptions,
    usersOptions,
}: {
    rolesOptions: { name: string; value: string }[];
    usersOptions: { name: string; value: string }[];
}) => {
    const { edit_data } = useAppSelector((state) => state?.widget_builder);
    const new_folder = edit_data?.data?.permissions?.new_folder;

    return (
        <BasePermissions
            enable={new_folder?.enable || false}
            enableTitle={__("New Folder", "ninja-drive")}
            enableDescription={__(
                "Allow users to create new folders.",
                "ninja-drive",
            )}
            filterDescription={__(
                "Select users & roles who can create new folders.",
                "ninja-drive",
            )}
            selectedAccessType={new_folder?.user_access || "everyone"}
            selectedUserType={new_folder?.logged_in_user_type || "users"}
            saveBaseKey="new_folder"
            rolesOptions={rolesOptions}
            usersOptions={usersOptions}
            selectedRolesOrUsers={new_folder?.display_for || []}
        />
    );
};

export default NewFolder;
