import CollapsibleField from "~/components/molecules/SettingsField/CollapsibleField";
import { updatePermissions } from "~/store/features/widgetBuilderSlice";
import SettingsField from "~/components/molecules/SettingsField";
import { useAppDispatch, useAppSelector } from "~/store/hooks";
import Description from "~/components/molecules/Description";
import InlineStack from "~/components/molecules/InlineStack";
import BlockStack from "~/components/molecules/BlockStack";
import { useEffect, useState } from "@wordpress/element";
import SelectBox from "~/components/molecules/SelectBox";
import { MBPermissions } from "~/types/widget.types";
import Switcher from "~/components/atoms/Switcher";
import Divider from "~/components/atoms/Divider";
import { toBoolean } from "~/utils/functions";
import Radio from "~/components/atoms/Radio";
import Text from "~/components/atoms/Text";
import Tabs from "~/components/atoms/Tabs";
import { __ } from "@wordpress/i18n";

interface BasePermissionsProps {
    enable: boolean;
    enableTitle: string;
    enableDescription: string;
    filterDescription: string;
    selectedAccessType: "everyone" | "logged";
    selectedUserType: "users" | "roles";
    saveBaseKey:
        | "new_folder"
        | "upload"
        | "preview"
        | "rename"
        | "download"
        | "copy"
        | "move"
        | "share"
        | "search"
        | "delete";
    rolesOptions: { name: string; value: string }[];
    usersOptions: { name: string; value: string }[];
    selectedRolesOrUsers: string[];
    extraContent?: React.ReactNode;
}

const BasePermissions = ({
    enable,
    enableTitle,
    enableDescription,
    selectedAccessType,
    selectedUserType,
    saveBaseKey,
    rolesOptions,
    usersOptions,
    selectedRolesOrUsers,
    extraContent,
}: BasePermissionsProps) => {
    const { edit_data } = useAppSelector((state) => state?.widget_builder);
    const [localUserType, setLocalUserType] = useState(selectedUserType);

    const dispatch = useAppDispatch();

    useEffect(() => {
        setLocalUserType(selectedUserType);
    }, [selectedUserType]);

    const handleUpdate = (
        key: keyof MBPermissions[typeof saveBaseKey],
        value: MBPermissions[typeof saveBaseKey][keyof MBPermissions[typeof saveBaseKey]],
    ) => {
        dispatch(
            updatePermissions({
                key: saveBaseKey,
                value: {
                    ...edit_data?.data?.permissions?.[saveBaseKey]!,
                    [key]: value,
                },
            }),
        );
    };

    return (
        <CollapsibleField
            collapsible
            open={enable}
            description={enableDescription}
            isPro={true}
            action={
                <Switcher
                    title={enableTitle}
                    isPro={true}
                    titleSize="sm"
                    checked={enable}
                    onChange={() => {
                        if (!toBoolean(pnpnd?.is_pro)) return;

                        handleUpdate("enable", !enable);
                    }}
                />
            }
        >
            <Divider width="100%" height="1px" marginTop={16} />

            {extraContent && extraContent}

            <InlineStack gap={10}>
                <Text color="gray-700" size="sm" weight="medium">
                    {__("Filter Users & Roles", "ninja-drive")}
                </Text>

                {["everyone", "logged"]?.map((type) => (
                    <Radio
                        key={type}
                        title={type}
                        checked={selectedAccessType === type}
                        onChange={() =>
                            handleUpdate(
                                "user_access",
                                type as "everyone" | "logged",
                            )
                        }
                    />
                ))}
            </InlineStack>

            {selectedAccessType === "logged" && (
                <SettingsField background="gray-50">
                    <InlineStack gap={10}>
                        <Text color="gray-700" size="sm" weight="medium">
                            {__("User Type", "ninja-drive")}
                        </Text>

                        <Tabs
                            background="white"
                            size="small"
                            rounded="md"
                            tabRounded="sm"
                            tabs={LOGGED_IN_USER_TYPES}
                            active={localUserType}
                            onTabClick={(value) => {
                                setLocalUserType(value as "users" | "roles");
                                handleUpdate(
                                    "logged_in_user_type",
                                    value as "users" | "roles",
                                );
                                handleUpdate("display_for", []);
                            }}
                        />
                    </InlineStack>

                    <BlockStack gap={10}>
                        <InlineStack gap={10}>
                            <Text color="gray-700" size="sm" weight="medium">
                                {`${__("Select", "ninja-drive")} ${
                                    localUserType === "roles"
                                        ? __("Roles", "ninja-drive")
                                        : __("Users", "ninja-drive")
                                }`}
                            </Text>

                            <SelectBox
                                options={
                                    localUserType === "roles"
                                        ? rolesOptions
                                        : usersOptions
                                }
                                value={[
                                    ...selectedRolesOrUsers,
                                    ...(localUserType === "roles"
                                        ? ["administrator"]
                                        : []),
                                ]}
                                requiredValue={
                                    localUserType === "roles"
                                        ? ["administrator"]
                                        : []
                                }
                                skipValues={["administrator"]}
                                onChange={(value) =>
                                    handleUpdate(
                                        "display_for",
                                        value as string[],
                                    )
                                }
                                size="small"
                                multiple
                                style={{
                                    minWidth: "150px",
                                }}
                            />
                        </InlineStack>

                        <Description
                            text={__(
                                "Select users to allow access. left empty to allow all logged in users.",
                                "ninja-drive",
                            )}
                        />
                    </BlockStack>
                </SettingsField>
            )}
        </CollapsibleField>
    );
};

export default BasePermissions;

const LOGGED_IN_USER_TYPES: {
    key: "roles" | "users";
    title: string;
    icon: string;
}[] = [
    {
        key: "roles",
        title: __("Roles", "ninja-drive"),
        icon: "manage_accounts",
    },
    {
        key: "users",
        title: __("Users", "ninja-drive"),
        icon: "person",
    },
];
