import BlockStack from "~/components/molecules/BlockStack";
import { useModuleFiles } from "~/hooks/useModuleFiles";
import { ModuleConfig } from "~/types/widget.types";
import Loading from "~/components/atoms/Loading";
import { useGallery } from "~/hooks/useGallery";
import type { CSSProperties } from "react";
import { File } from "~/types/file.types";
import clsx from "clsx";
import {
    useEffect,
    useRef,
    useLayoutEffect,
    useState,
} from "@wordpress/element";

const SliderCarousel = ({ data }: { data: ModuleConfig }) => {
    const {
        style: { slider_carousel },
    } = data?.data || {};
    const { files, loading, has_more, loadMore, loadingMore, queryArgs } =
        useModuleFiles(data, "", ["image"], true);
    const [swiperReady, setSwiperReady] = useState(false);
    const { preview } = data?.data?.permissions || {};

    const { viewFile } = useGallery(files, data?.id, {
        showThumbnails: preview?.preview_thumbnail,
    });

    const {
        slider_direction,
        slider_type,
        slider_effect,
        navigation_style,
        slide_to_show,
        item_gap,
        border_radius,
        slide_auto_play,
        auto_play_speed,
        show_overlay,
        show_slider_caption,
        infinite_loop,
        mouse_control,
    } = slider_carousel || {};

    const isOneItem = slider_effect === "flip" || slider_effect === "fade";

    const direction = slider_direction || "horizontal";
    const type = isOneItem ? "normal" : slider_type || "normal";
    const effect = slider_effect || "slide";
    const navStyle = navigation_style || "arrows-dots";
    const isPaginationEnabled =
        navStyle === "arrows-dots" || navStyle === "dots";
    const isNavigationEnabled =
        navStyle === "arrows-dots" || navStyle === "arrows";
    const desktopSlides = isOneItem ? 1 : slide_to_show?.desktop || 1;
    const tabletSlides = isOneItem ? 1 : slide_to_show?.tablet || 1;
    const mobileSlides = isOneItem ? 1 : slide_to_show?.mobile || 1;
    const slideGap = item_gap || 0;
    const radius = border_radius || 0;
    const isAutoPlay = slide_auto_play || false;
    const playSpeed = auto_play_speed || 3000;
    const showCaption = show_slider_caption && show_overlay;

    const swiperRef = useRef<HTMLDivElement | null>(null);
    const swiperInstance = useRef<any>(null);
    const appendedCount = useRef(0);

    const hasMoreRef = useRef(has_more);
    const loadingMoreRef = useRef(loadingMore);
    const viewFileRef = useRef(viewFile);

    useEffect(() => {
        viewFileRef.current = viewFile;
    }, [viewFile]);

    useEffect(() => {
        hasMoreRef.current = has_more;
        loadingMoreRef.current = loadingMore;
    }, [has_more, loadingMore]);

    useLayoutEffect(() => {
        if (swiperInstance.current) return;

        const tryInit = () => {
            if (!swiperRef.current || !window.Swiper) {
                return false;
            }

            swiperInstance.current = new window.Swiper(swiperRef.current, {
                slidesPerView: desktopSlides,
                spaceBetween: slideGap,
                grabCursor: true,
                direction: direction,
                effect: effect,
                creativeEffect: effect === "creative" && {
                    prev: {
                        shadow: true,
                        translate: [0, 0, -400],
                    },
                    next: {
                        translate: ["100%", 0, 0],
                    },
                },
                centeredSlides: type === "centered",
                loop: infinite_loop,
                autoplay: isAutoPlay
                    ? {
                          delay: playSpeed,
                      }
                    : false,
                breakpoints: {
                    0: { slidesPerView: mobileSlides },
                    768: { slidesPerView: tabletSlides },
                    1024: { slidesPerView: desktopSlides },
                },
                pagination: isPaginationEnabled
                    ? {
                          el: swiperRef.current!.querySelector(
                              ".swiper-pagination",
                          ),
                          clickable: true,
                      }
                    : false,
                navigation: isNavigationEnabled
                    ? {
                          nextEl: swiperRef.current!.querySelector(
                              ".swiper-button-next",
                          ),
                          prevEl: swiperRef.current!.querySelector(
                              ".swiper-button-prev",
                          ),
                      }
                    : false,

                on: {
                    reachEnd: (swiper: any) => {
                        // Prevent initial fire when slides are empty or not enough
                        if (
                            swiper.slides.length <= swiper.params.slidesPerView
                        ) {
                            return;
                        }

                        if (hasMoreRef.current && !loadingMoreRef.current) {
                            loadMore();
                        }
                    },

                    tap: (_swiper: any, event: any) => {
                        const file_key = event.target.getAttribute("data-id");
                        if (!file_key) return;
                        if (mouse_control) {
                            preview?.enable &&
                                preview?.inline &&
                                viewFileRef.current?.(file_key);
                        }
                    },
                },
            });

            setSwiperReady(true);
            return true;
        };

        if (tryInit()) return;

        const interval = setInterval(() => {
            if (tryInit()) {
                clearInterval(interval);
            }
        }, 50);

        return () => {
            clearInterval(interval);
            swiperInstance.current?.destroy(true, true);
            swiperInstance.current = null;
            setSwiperReady(false);
        };
    }, [data]);

    const getThumbnailUrlByQuality = (
        file: File,
        quality: "original" | "large" | "medium" | "thumbnail",
    ): string => {
        const suffixMap = {
            original: "5xl",
            large: "4xl",
            medium: "md",
            thumbnail: "",
        };

        return PNPNDHelper.getUrl(
            "thumbnail",
            file.file_key,
            file.name,
            data.id,
            suffixMap[quality] as
                | "5xl"
                | "4xl"
                | "md"
                | "sm"
                | "lg"
                | "xl"
                | "2xl"
                | "3xl",
            file.extension,
        );
    };

    useEffect(() => {
        if (!swiperReady) return;
        if (!swiperInstance.current) return;
        if (!files.length) return;

        const slides = files.map((file) => {
            const imgSrc = getThumbnailUrlByQuality(
                file,
                slider_carousel?.thumbnail_quality || "thumbnail",
            );

            return `
    <div class="swiper-slide">
        <div class="pnpnd-img-wrapper pnpnd-img-loading">
            ${
                slider_carousel?.show_overlay
                    ? '<div class="pnpnd-slide-overlay"></div>'
                    : ""
            }

            <div class="pnpnd-skeleton"></div>

            <img 
                src="${imgSrc}"
                alt="${file.name}"
                loading="lazy"
                data-id="${file.file_key}"
                onload="this.parentElement.classList.remove('pnpnd-img-loading')"
                onerror="this.parentElement.classList.add('error')"
            />

            ${
                show_slider_caption && file.name
                    ? `<figcaption class="pnpnd-slide-caption">${file.name}</figcaption>`
                    : ""
            }
        </div>
    </div>
    `;
        });
        swiperInstance.current.appendSlide(slides);
        swiperInstance.current.update();

        appendedCount.current = files.length;
        if (isAutoPlay) {
            swiperInstance.current.autoplay?.stop();
            swiperInstance.current.autoplay?.start();
        }
    }, [files, swiperReady]);

    if (loading && !files.length) {
        return (
            <BlockStack
                className="w-full h-full"
                align="center"
                inlineAlign="center"
            >
                <Loading />
            </BlockStack>
        );
    }

    return (
        <div
            ref={swiperRef}
            style={
                {
                    "--item-border-radius": `${radius}px`,
                } as CSSProperties
            }
            className={clsx(
                "swiper",
                `pnpnd-swiper--${type}`,
                `pnpnd-swiper-effect--${effect}`,
            )}
        >
            <div className="swiper-wrapper" />
            <div className="swiper-pagination" />
            <div className="swiper-button-prev" />
            <div className="swiper-button-next" />
        </div>
    );
};

export default SliderCarousel;
