import { ServerResponse } from "~/types/Types";
import { File } from "~/types/file.types";
import { baseApi } from "./baseApi";

export const mediaLibraryApi = baseApi.injectEndpoints({
    endpoints: (builder) => ({
        getMediaFolder: builder.query<
            ServerResponse<any>,
            {
                folder_key: string;
                order_by?: "name" | "size" | "created_at" | "updated_at";
                order?: "ASC" | "DESC";
            }
        >({
            query: ({ folder_key, order_by, order }) => {
                const params = {
                    folder_key: folder_key === "/" ? "" : folder_key,
                    order_by: order_by || "name",
                    order: order || "ASC",
                };

                return {
                    url: "media-library",
                    method: "GET",
                    params,
                };
            },

            serializeQueryArgs: ({ queryArgs }) => {
                return `media-folder-${queryArgs.folder_key}`;
            },

            forceRefetch: ({ currentArg, previousArg }) => {
                if (!previousArg) return false;

                return (
                    currentArg?.order !== previousArg.order ||
                    currentArg?.order_by !== previousArg.order_by
                );
            },

            providesTags: () => ["MediaFolders"],
        }),

        addMediaFolder: builder.mutation<
            ServerResponse<File>,
            { file_key: string; name: string }
        >({
            query: ({ file_key, name }) => {
                return {
                    url: "folder/create",
                    method: "POST",
                    body: { file_key, name },
                };
            },

            async onQueryStarted({ file_key }, { dispatch, queryFulfilled }) {
                try {
                    const { data } = await queryFulfilled;

                    dispatch(
                        mediaLibraryApi.util.updateQueryData(
                            "getMediaFolder",
                            { folder_key: file_key === "/" ? "" : file_key },
                            (draft) => {
                                if (!draft?.data?.files) return;
                                const new_folder = data?.data;
                                if (!new_folder) return;
                                draft.data.files.unshift(new_folder);
                            },
                        ),
                    );
                } catch (error) {
                    // error
                }
            },
        }),

        renameMediaFolder: builder.mutation<
            ServerResponse<File>,
            { file_key: string; name: string; parentKey: string }
        >({
            query: ({ file_key, name }) => {
                return {
                    url: "file/rename",
                    method: "POST",
                    body: { file_key, name },
                };
            },

            async onQueryStarted(
                { file_key, parentKey },
                { dispatch, queryFulfilled },
            ) {
                try {
                    const { data } = await queryFulfilled;

                    dispatch(
                        mediaLibraryApi.util.updateQueryData(
                            "getMediaFolder",
                            { folder_key: parentKey === "/" ? "" : parentKey },
                            (draft) => {
                                if (!draft?.data?.files) return;

                                const renamedFile = data?.data;
                                if (!renamedFile) return;

                                const index = draft.data.files.findIndex(
                                    (f: File) => f.file_key === file_key,
                                );

                                if (index === -1) return;

                                draft.data.files[index] = renamedFile;
                            },
                        ),
                    );
                } catch (error) {
                    // error
                }
            },
        }),

        deleteMediaFolder: builder.mutation<
            ServerResponse<null>,
            { folderKeys: string[]; parentKey: string }
        >({
            query: ({ folderKeys }) => {
                return {
                    url: "file",
                    method: "DELETE",
                    body: { file_keys: folderKeys },
                };
            },

            async onQueryStarted(
                { folderKeys, parentKey },
                { dispatch, queryFulfilled },
            ) {
                try {
                    await queryFulfilled;

                    dispatch(
                        mediaLibraryApi.util.updateQueryData(
                            "getMediaFolder",
                            { folder_key: parentKey === "/" ? "" : parentKey },
                            (draft) => {
                                if (!draft?.data?.files) return;
                                draft.data.files = draft.data.files.filter(
                                    (f: File) =>
                                        !folderKeys.includes(f.file_key),
                                );
                            },
                        ),
                    );
                } catch (error) {
                    // error
                }
            },
        }),

        uploadToMediaLibrary: builder.mutation<
            ServerResponse<any>,
            { file_keys: string[]; extension?: string }
        >({
            query: ({ file_keys, extension }) => {
                return {
                    url: "media-library/import",
                    method: "POST",
                    body: { file_keys, extension },
                };
            },
        }),

        trashFiles: builder.mutation<
            ServerResponse<any>,
            { file_keys: string[] }
        >({
            query: ({ file_keys }) => {
                return {
                    url: "media-library/trash",
                    method: "DELETE",
                    body: { attachment_ids: file_keys },
                };
            },
        }),

        restoreFiles: builder.mutation<
            ServerResponse<any>,
            { file_keys: string[] }
        >({
            query: ({ file_keys }) => {
                return {
                    url: "media-library/restore",
                    method: "POST",
                    body: { attachment_ids: file_keys },
                };
            },
        }),

        removeFiles: builder.mutation<
            ServerResponse<any>,
            { file_keys: string[] }
        >({
            query: ({ file_keys }) => {
                return {
                    url: "media-library",
                    method: "DELETE",
                    body: { attachment_ids: file_keys },
                };
            },
        }),

        addMediaLibraryFolder: builder.mutation<
            ServerResponse<void>,
            { folder_keys: string[] }
        >({
            query: ({ folder_keys }) => {
                return {
                    url: "media-library/set-folders",
                    method: "POST",
                    body: { folder_keys: folder_keys },
                };
            },

            invalidatesTags: ["MediaFolders", "Settings"],
        }),

        mediaLibrarySync: builder.mutation<ServerResponse<null>, void>({
            query: () => ({
                url: "media-library/sync",
                method: "POST",
            }),
        }),

        clearAttachments: builder.mutation<void, void>({
            query: () => ({
                url: "media-library/clear",
                method: "DELETE",
            }),
        }),
    }),

    overrideExisting: false,
});

export const {
    useGetMediaFolderQuery,
    useLazyGetMediaFolderQuery,
    useAddMediaFolderMutation,
    useRenameMediaFolderMutation,
    useDeleteMediaFolderMutation,
    useUploadToMediaLibraryMutation,
    useTrashFilesMutation,
    useRestoreFilesMutation,
    useRemoveFilesMutation,
    useAddMediaLibraryFolderMutation,
    useMediaLibrarySyncMutation,
    useClearAttachmentsMutation,
} = mediaLibraryApi;
